function LoginScreen({ students, onLogin }) {
  const [role, setRole] = useState("student");
  const [loginId, setLoginId] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");

  function selectRole(nextRole) {
    setRole(nextRole);
    setError("");
    setLoginId("");
    setPassword("");
  }

  async function submit(event) {
    event.preventDefault();
    const result = await onLogin(role, loginId.trim(), password.trim());
    if (!result.ok) setError(result.message);
  }

  const roleLabels = {
    student: "학생",
    parent: "학부모",
    teacher: "선생님"
  };

  return (
    <main className="loginPage">
      <form className="loginCard" onSubmit={submit}>
        <button className="loginClose" type="button">×</button>
        <p className="loginEyebrow">{academyBrandName}</p>
        <h1>로그인</h1>
        <div className="loginTabs">
          {["student", "parent", "teacher"].map((item) => (
            <button className={role === item ? "active" : ""} key={item} onClick={() => selectRole(item)} type="button">
              {roleLabels[item]}
            </button>
          ))}
        </div>
        <p className="muted">
          {role === "student" ? "학생은 학원 번호를 붙여 로그인합니다." : null}
          {role === "parent" ? "학부모는 자녀 계정과 연결된 보호자 계정으로 로그인합니다." : null}
          {role === "teacher" ? "선생님은 운영자 계정으로 로그인합니다." : null}
        </p>
        <input value={loginId} onChange={(event) => setLoginId(event.target.value)} placeholder="아이디" />
        <input type="password" value={password} onChange={(event) => setPassword(event.target.value)} placeholder="비밀번호" />
        {error ? <div className="loginError">{error}</div> : null}
        <button className="primaryButton full" type="submit">{roleLabels[role]} 로그인</button>
      </form>
    </main>
  );
}

function RoleLoginScreen({ initialRole = "student", onLogin }) {
  const [role, setRole] = useState(initialRole);
  const [loginId, setLoginId] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");
  const [isSubmitting, setIsSubmitting] = useState(false);

  const roleLabels = {
    student: "학생",
    parent: "학부모",
    teacher: "선생님"
  };

  function selectRole(nextRole) {
    setRole(nextRole);
    setLoginId("");
    setPassword("");
    setError("");
  }

  async function submit(event) {
    event.preventDefault();
    setIsSubmitting(true);
    try {
      const result = await onLogin(role, loginId.trim(), password.trim());
      if (!result.ok) {
        setError(result.message);
        return;
      }
    } finally {
      setIsSubmitting(false);
    }
  }

  return (
    <main className="loginPage">
      <form className="loginCard" onSubmit={submit}>
        <button className="loginClose" type="button">x</button>
        <p className="loginEyebrow">{academyBrandName}</p>
        <h1>로그인</h1>
        <div className="loginTabs">
          {["student", "parent", "teacher"].map((item) => (
            <button
              className={role === item ? "active" : ""}
              key={item}
              onClick={() => selectRole(item)}
              type="button"
            >
              {roleLabels[item]}
            </button>
          ))}
        </div>
        <p className="muted">
          {role === "student" ? "학생 본인 계정으로 입장합니다." : null}
          {role === "parent" ? "학부모 열람 계정으로 입장합니다." : null}
          {role === "teacher" ? "강사 운영 화면으로 입장합니다." : null}
        </p>
        <input value={loginId} onChange={(event) => setLoginId(event.target.value)} placeholder="아이디" />
        <input
          type="password"
          value={password}
          onChange={(event) => setPassword(event.target.value)}
          placeholder="비밀번호"
        />
        {error ? <div className="loginError">{error}</div> : null}
        <button className="primaryButton full" disabled={isSubmitting} type="submit">
          {isSubmitting ? "확인 중" : `${roleLabels[role]} 로그인`}
        </button>
      </form>
    </main>
  );
}

function AcademyReminderList({
  emptyText = "표시할 운영 알림이 없습니다.",
  onDeleteAcademyReminder,
  onEditAcademyReminder,
  onSaveAcademyReminder,
  reminders = [],
  showActions = false,
  students = [],
  templates = []
}) {
  const [busyReminderId, setBusyReminderId] = useState("");
  const [actionError, setActionError] = useState("");
  const safeReminders = Array.isArray(reminders) ? reminders.filter(Boolean) : [];

  async function markDone(reminder) {
    const reminderId = reminder?.reminderId || reminder?.id || "";
    if (busyReminderId) return;
    if (!reminderId) {
      setActionError("운영 알림 ID가 없어 완료 처리할 수 없습니다. 새로고침 후 다시 시도해 주세요.");
      return;
    }
    setBusyReminderId(reminderId);
    setActionError("");
    try {
      await onSaveAcademyReminder?.(normalizeAcademyReminderDraft({
        ...reminder,
        reminderId,
        id: reminderId,
        status: "done",
        completedAt: new Date().toISOString()
      }));
    } catch (error) {
      console.error("Failed to mark academy reminder done", error);
      setActionError(`운영 알림 완료 실패 · ${error?.message || "알 수 없는 오류"}`);
    } finally {
      setBusyReminderId("");
    }
  }

  async function removeReminder(reminder) {
    const reminderId = reminder?.reminderId || reminder?.id || "";
    if (busyReminderId) return;
    if (!reminderId) {
      setActionError("운영 알림 ID가 없어 삭제할 수 없습니다. 새로고침 후 다시 시도해 주세요.");
      return;
    }
    setBusyReminderId(reminderId);
    setActionError("");
    try {
      await onDeleteAcademyReminder?.(reminderId);
    } catch (error) {
      console.error("Failed to delete academy reminder", error);
      setActionError(`운영 알림 삭제 실패 · ${error?.message || "알 수 없는 오류"}`);
    } finally {
      setBusyReminderId("");
    }
  }

  if (!safeReminders.length) {
    return <EmptyState className="emptyState academyReminderEmpty">{emptyText}</EmptyState>;
  }

  return (
    <div className="academyReminderList">
      {actionError ? <div className="academyReminderActionError">{actionError}</div> : null}
      {sortAcademyReminders(safeReminders).map((rawReminder) => {
        const reminderId = rawReminder.reminderId || rawReminder.id || "";
        const reminder = normalizeAcademyReminderDraft(reminderId ? { ...rawReminder, reminderId, id: reminderId } : rawReminder);
        const status = normalizeAcademyReminderStatus(reminder.status);
        const studentName = getAcademyReminderStudentName(reminder, students);
        const className = getAcademyReminderClassName(reminder, templates);
        return (
          <article className={`academyReminderItem status-${status} priority-${reminder.priority || "normal"}`} key={reminderId || reminder.reminderId}>
            <div className="academyReminderItemMain">
              <div className="academyReminderItemTop">
                <span className="academyReminderType">{getAcademyReminderTypeLabel(reminder.reminderType ?? reminder.type)}</span>
                <strong>{reminder.title || "운영 알림"}</strong>
                <span className="academyReminderDateTime">{formatAcademyReminderDateTime(reminder)}</span>
              </div>
              <p>{reminder.content || reminder.memo || "내용 없음"}</p>
              <div className="academyReminderMeta">
                {studentName ? <span>학생 {studentName}</span> : null}
                {className ? <span>반 {className}</span> : null}
                <span>{getAcademyReminderPriorityLabel(reminder.priority)}</span>
                <span>{academyReminderStatusLabels[status]}</span>
                <span>{reminder.slackNotify === false ? "슬랙 제외" : "09:00 슬랙 포함"}</span>
              </div>
            </div>
            {showActions ? (
              <div className="academyReminderActions">
                <button
                  className="softButton compact"
                  disabled={!reminderId || busyReminderId === reminderId}
                  onClick={() => onEditAcademyReminder?.(reminder)}
                  type="button"
                >
                  수정
                </button>
                <button
                  className="softButton compact"
                  disabled={status === "done" || !reminderId || busyReminderId === reminderId}
                  onClick={() => markDone(reminder)}
                  type="button"
                >
                  {busyReminderId === reminderId ? "처리 중" : "완료"}
                </button>
                <button
                  className="dangerSoftButton compact"
                  disabled={!reminderId || busyReminderId === reminderId}
                  onClick={() => removeReminder(reminder)}
                  type="button"
                >
                  삭제
                </button>
              </div>
            ) : null}
          </article>
        );
      })}
    </div>
  );
}

function AcademyReminderPanel({
  reminders = [],
  selectedDate = today,
  students = [],
  templates = [],
  onDeleteAcademyReminder,
  onSaveAcademyReminder
}) {
  const [draft, setDraft] = useState(() => createAcademyReminderDraft(selectedDate));
  const [editingReminderId, setEditingReminderId] = useState("");
  const [isReminderFormOpen, setIsReminderFormOpen] = useState(false);
  const [saveState, setSaveState] = useState("idle");
  const [saveMessage, setSaveMessage] = useState("");
  const isEditingReminder = Boolean(editingReminderId);
  const shouldShowReminderForm = isReminderFormOpen || isEditingReminder;
  const activeStudents = students.filter(isActiveStudent);
  const activeClassTemplates = templates.filter((template) => template?.classTemplateId);
  const isClassReminderDraft = draft.reminderType === "class_notice";
  const selectedClassTemplateId = getAcademyReminderClassTemplateId(draft);
  const overdueReminders = sortAcademyReminders(reminders).filter((reminder) => isAcademyReminderOverdue(reminder));
  const selectedDateReminders = getAcademyRemindersForDate(reminders, selectedDate)
    .filter((reminder) => !isAcademyReminderOverdue(reminder));
  const upcomingReminders = sortAcademyReminders(reminders)
    .filter((reminder) => normalizeAcademyReminderStatus(reminder.status) === "pending")
    .filter((reminder) => (reminder.reminderDate || reminder.date || "") >= today)
    .filter((reminder) => !isAcademyReminderOverdue(reminder))
    .slice(0, 8);

  useEffect(() => {
    if (editingReminderId) return;
    setDraft((current) => ({ ...current, reminderDate: selectedDate || today, date: selectedDate || today }));
  }, [editingReminderId, selectedDate]);

  function updateDraft(field, value) {
    setSaveState(isEditingReminder ? "dirty" : "idle");
    setSaveMessage(isEditingReminder ? "운영 알림 수정 중 · 저장 전" : "");
    setDraft((current) => ({ ...current, [field]: value }));
  }

  function updateReminderType(nextType) {
    setSaveState(isEditingReminder ? "dirty" : "idle");
    setSaveMessage(isEditingReminder ? "운영 알림 수정 중 · 저장 전" : "");
    setDraft((current) => {
      const sourcePayload = { ...getAcademyReminderSourcePayload(current) };
      if (nextType === "class_notice") {
        return {
          ...current,
          reminderType: nextType,
          studentId: "",
          sourcePayload
        };
      }
      delete sourcePayload.classTemplateId;
      delete sourcePayload.classId;
      delete sourcePayload.className;
      return {
        ...current,
        reminderType: nextType,
        classTemplateId: "",
        sourcePayload
      };
    });
  }

  function updateReminderStudentTarget(studentId) {
    setSaveState(isEditingReminder ? "dirty" : "idle");
    setSaveMessage(isEditingReminder ? "운영 알림 수정 중 · 저장 전" : "");
    setDraft((current) => {
      const sourcePayload = { ...getAcademyReminderSourcePayload(current) };
      delete sourcePayload.classTemplateId;
      delete sourcePayload.classId;
      delete sourcePayload.className;
      return {
        ...current,
        classTemplateId: "",
        studentId,
        sourcePayload
      };
    });
  }

  function updateReminderClassTarget(classTemplateId) {
    const selectedTemplate = activeClassTemplates.find((template) => template.classTemplateId === classTemplateId);
    setSaveState(isEditingReminder ? "dirty" : "idle");
    setSaveMessage(isEditingReminder ? "운영 알림 수정 중 · 저장 전" : "");
    setDraft((current) => {
      const sourcePayload = { ...getAcademyReminderSourcePayload(current) };
      if (classTemplateId) {
        sourcePayload.classTemplateId = classTemplateId;
        sourcePayload.className = selectedTemplate?.name ?? sourcePayload.className ?? "";
      } else {
        delete sourcePayload.classTemplateId;
        delete sourcePayload.classId;
        delete sourcePayload.className;
      }
      return {
        ...current,
        classTemplateId,
        studentId: "",
        sourcePayload
      };
    });
  }

  function startEditReminder(reminder) {
    const normalized = normalizeAcademyReminderDraft(reminder);
    setEditingReminderId(normalized.reminderId);
    setIsReminderFormOpen(true);
    setDraft(getAcademyReminderClassTemplateId(normalized) ? { ...normalized, reminderType: "class_notice" } : normalized);
    setSaveState("dirty");
    setSaveMessage("운영 알림 수정 중 · 저장 전");
  }

  function cancelEditReminder() {
    setEditingReminderId("");
    setIsReminderFormOpen(false);
    setDraft(createAcademyReminderDraft(selectedDate || today));
    setSaveState("idle");
    setSaveMessage("");
  }

  async function saveDraft() {
    const status = normalizeAcademyReminderStatus(draft.status);
    if (draft.reminderType === "class_notice" && !selectedClassTemplateId) {
      setSaveState("failed");
      setSaveMessage("반 알림 저장 실패 · 반을 선택하세요.");
      return;
    }
    const selectedTemplate = activeClassTemplates.find((template) => template.classTemplateId === selectedClassTemplateId);
    const sourcePayload = { ...getAcademyReminderSourcePayload(draft) };
    if (draft.reminderType === "class_notice" && selectedClassTemplateId) {
      sourcePayload.classTemplateId = selectedClassTemplateId;
      sourcePayload.className = selectedTemplate?.name ?? sourcePayload.className ?? "";
    } else {
      delete sourcePayload.classTemplateId;
      delete sourcePayload.classId;
      delete sourcePayload.className;
    }
    const reminderToSave = normalizeAcademyReminderDraft({
      ...draft,
      classTemplateId: draft.reminderType === "class_notice" ? selectedClassTemplateId : "",
      reminderId: editingReminderId || draft.reminderId,
      id: editingReminderId || draft.reminderId,
      sourcePayload,
      studentId: draft.reminderType === "class_notice" ? "" : draft.studentId,
      completedAt: status === "done" ? (draft.completedAt || new Date().toISOString()) : "",
      status
    });
    setSaveState("saving");
    setSaveMessage(isEditingReminder ? "운영 알림을 수정 저장하는 중입니다." : "운영 알림을 저장하는 중입니다.");
    try {
      const saved = await onSaveAcademyReminder?.(reminderToSave);
      const nextDate = saved?.reminderDate || reminderToSave.reminderDate || selectedDate || today;
      setEditingReminderId("");
      setIsReminderFormOpen(false);
      setSaveState("saved");
      setSaveMessage(isEditingReminder ? "운영 알림 · 수정 완료" : "운영 알림 · 저장 완료");
      setDraft(createAcademyReminderDraft(nextDate));
    } catch (error) {
      setSaveState("failed");
      setSaveMessage(`운영 알림 ${isEditingReminder ? "수정" : "저장"} 실패 · ${error?.message || "알 수 없는 오류"}`);
    }
  }

  return (
    <section className="panel academyReminderPanel">
      <div className="sectionHeader slim">
        <div>
          <p className="eyebrow">OPERATIONS SOURCE</p>
          <h2>운영 알림 원본</h2>
          <p className="muted">상담 일정, 신입생 일정, 특이사항 알림을 한 곳에 저장하고 각 화면과 09:00 슬랙 요약에서 읽습니다.</p>
        </div>
        <div className="academyReminderHeaderActions">
          <span className={`saveStateBadge ${saveState === "saved" ? "success" : saveState}`}>{saveMessage || "Supabase academy_reminders"}</span>
          <button
            className="softButton compact"
            disabled={isEditingReminder}
            onClick={() => setIsReminderFormOpen((current) => !current)}
            title={isEditingReminder ? "수정 중에는 수정 취소 또는 저장을 먼저 선택하세요." : undefined}
            type="button"
          >
            {shouldShowReminderForm ? "입력 접기" : "알림 입력 열기"}
          </button>
        </div>
      </div>
      {overdueReminders.length > 0 ? (
        <section className="academyReminderOverdueSection">
          <div className="miniSectionHeader">
            <strong>처리 지연 알림</strong>
            <span>{overdueReminders.length}건 · 먼저 처리</span>
          </div>
          <AcademyReminderList
            emptyText="처리 지연 알림이 없습니다."
            onDeleteAcademyReminder={onDeleteAcademyReminder}
            onEditAcademyReminder={startEditReminder}
            onSaveAcademyReminder={onSaveAcademyReminder}
            reminders={overdueReminders}
            showActions
            students={students}
            templates={templates}
          />
        </section>
      ) : null}
      {isEditingReminder ? (
        <div className="academyReminderEditBanner">
          <div>
            <strong>운영 알림 수정 중</strong>
            <span>같은 reminderId를 유지해 날짜, 시간, 내용만 수정 저장합니다.</span>
          </div>
          <button className="softButton compact" disabled={saveState === "saving"} onClick={cancelEditReminder} type="button">
            수정 취소
          </button>
        </div>
      ) : null}
      {shouldShowReminderForm ? (
        <div className="academyReminderForm">
          <select value={draft.reminderType} onChange={(event) => updateReminderType(event.target.value)}>
            {academyReminderTypeOptions.map((option) => (
              <option key={option.value} value={option.value}>{option.label}</option>
            ))}
          </select>
          {isClassReminderDraft ? (
            <select value={selectedClassTemplateId} onChange={(event) => updateReminderClassTarget(event.target.value)}>
              <option value="">반 선택</option>
              {activeClassTemplates.map((template) => (
                <option key={template.classTemplateId} value={template.classTemplateId}>{template.name}</option>
              ))}
            </select>
          ) : (
            <select value={draft.studentId} onChange={(event) => updateReminderStudentTarget(event.target.value)}>
              <option value="">학생 선택 없음</option>
              {activeStudents.map((student) => (
                <option key={student.studentId} value={student.studentId}>{student.name}</option>
              ))}
            </select>
          )}
          <input
            value={draft.title}
            onChange={(event) => updateDraft("title", event.target.value)}
            placeholder="알림 제목"
          />
          <input type="date" value={draft.reminderDate} onChange={(event) => updateDraft("reminderDate", event.target.value)} />
          <input type="time" value={draft.reminderTime} onChange={(event) => updateDraft("reminderTime", event.target.value)} />
          <select value={draft.priority} onChange={(event) => updateDraft("priority", event.target.value)}>
            {academyReminderPriorityOptions.map((option) => (
              <option key={option.value} value={option.value}>{option.label}</option>
            ))}
          </select>
          <select value={draft.status} onChange={(event) => updateDraft("status", event.target.value)}>
            {Object.entries(academyReminderStatusLabels).map(([value, label]) => (
              <option key={value} value={value}>{label}</option>
            ))}
          </select>
          <label className="academyReminderSlackToggle">
            <input
              checked={draft.slackNotify !== false}
              onChange={(event) => updateDraft("slackNotify", event.target.checked)}
              type="checkbox"
            />
            09:00 슬랙 포함
          </label>
          <textarea
            value={draft.content}
            onChange={(event) => updateDraft("content", event.target.value)}
            placeholder="내용을 입력하세요. 예: 상담 주제, 학부모 요청, 신입생 준비물, 당일 확인할 특이사항"
            rows="3"
          />
          <button
            className="primaryButton"
            disabled={!String(draft.title || draft.content).trim() || saveState === "saving" || (isClassReminderDraft && !selectedClassTemplateId)}
            onClick={saveDraft}
            type="button"
          >
            {saveState === "saving" ? "저장 중" : isEditingReminder ? "수정 저장" : "운영 알림 저장"}
          </button>
        </div>
      ) : null}
      <div className="academyReminderColumns">
        <section>
          <div className="miniSectionHeader">
            <strong>{selectedDate} 알림</strong>
            <span>{selectedDateReminders.length}건</span>
          </div>
          <AcademyReminderList
            onDeleteAcademyReminder={onDeleteAcademyReminder}
            onEditAcademyReminder={startEditReminder}
            onSaveAcademyReminder={onSaveAcademyReminder}
            reminders={selectedDateReminders}
            showActions
            students={students}
            templates={templates}
          />
        </section>
        <section>
          <div className="miniSectionHeader">
            <strong>다가오는 알림</strong>
            <span>{upcomingReminders.length}건</span>
          </div>
          <AcademyReminderList
            emptyText="대기 중인 운영 알림이 없습니다."
            onDeleteAcademyReminder={onDeleteAcademyReminder}
            onEditAcademyReminder={startEditReminder}
            onSaveAcademyReminder={onSaveAcademyReminder}
            reminders={upcomingReminders}
            showActions
            students={students}
            templates={templates}
          />
        </section>
      </div>
    </section>
  );
}

function TeacherLessonHubV2({
  academyReminders = [],
  academyTests = [],
  aiSettings,
  allRecords = [],
  attendanceSettings = defaultAttendanceSettings,
  generatedLessonSaveStatus = { lessons: [], message: "", state: "idle" },
  integrationStatus,
  lessonNotificationPlans = {},
  clipboardCount,
  lessons,
  makeupTasks = [],
  materials = [],
  notificationJobs = [],
  records,
  saveStates,
  selectedDate,
  selectedLesson,
  selectedLessonId,
  students,
  templates = [],
  testAttempts = [],
  testSessions = [],
  homeworks,
  onAddLesson,
  onBackToCalendar,
  onCancelNotificationJob,
  onChangeRecord,
  onCopyLesson,
  onDateSelect,
  onDeleteLesson,
  onDeleteAcademyReminder,
  onDeleteSelectedLesson,
  onEditLesson,
  onMoveDate,
  onOpenAttendance,
  onOpenExamPrep,
  onOpenLessonJournal,
  onOpenReport,
  onPasteLesson,
  onPassMakeupTask,
  onPolishComment,
  onReconcileSolapiNotificationResults,
  onRetryGeneratedLessonSave,
  onApplyLessonNotificationPlan,
  onScheduleMakeupTask,
  onSaveRecord,
  onSaveLessonJournalDrafts,
  onSaveAcademyReminder,
  onScheduleLessonNotificationsAt,
  onSendComment,
  onSelectLesson,
  onUndoLessonAction,
  onUpdateHomework,
  onUpdateLessonNotificationPlan,
  onUpdateMakeupTask,
  onToggleStudentNotificationMute,
  undoCount,
  isLessonJournalOpen
}) {
  const [lessonTypeFilter, setLessonTypeFilter] = useState("all");
  useEffect(() => {
    function isEditableTarget(target) {
      const tagName = target?.tagName?.toLowerCase();
      return tagName === "input" || tagName === "textarea" || tagName === "select" || target?.isContentEditable;
    }

    function handleKeyDown(event) {
      if (isLessonJournalOpen || isEditableTarget(event.target)) return;
      const key = event.key.toLowerCase();
      const isControl = event.ctrlKey || event.metaKey;

      if (isControl && key === "c") {
        event.preventDefault();
        onCopyLesson();
        return;
      }
      if (isControl && key === "v") {
        event.preventDefault();
        onPasteLesson();
        return;
      }
      if (isControl && key === "z") {
        event.preventDefault();
        onUndoLessonAction();
        return;
      }
      if (event.key === "Delete") {
        event.preventDefault();
        onDeleteSelectedLesson();
        return;
      }
      if (event.key === "Enter" && selectedLessonId) {
        event.preventDefault();
        onOpenLessonJournal(selectedLessonId);
        return;
      }
      const movementMap = {
        ArrowLeft: -1,
        ArrowRight: 1,
        ArrowUp: -7,
        ArrowDown: 7
      };
      if (movementMap[event.key]) {
        event.preventDefault();
        onMoveDate(movementMap[event.key]);
      }
    }

    window.addEventListener("keydown", handleKeyDown);
    return () => window.removeEventListener("keydown", handleKeyDown);
  }, [
    isLessonJournalOpen,
    onCopyLesson,
    onDeleteSelectedLesson,
    onMoveDate,
    onOpenLessonJournal,
    onPasteLesson,
    onUndoLessonAction,
    selectedLessonId
  ]);

  const selectedMakeupTask = selectedLesson
    ? makeupTasks.find((task) => task.makeupTaskId === selectedLesson.sourceMakeupTaskId || task.linkedLessonId === selectedLesson.lessonId)
    : null;
  const isSupplementMakeupLesson = isSupplementMakeupTaskLesson(selectedLesson, selectedMakeupTask);
  const isExamPrepLessonSelected = isExamPrepLesson(selectedLesson);
  const lessonJournalDialog = isLessonJournalOpen && selectedLesson ? (
    isSupplementMakeupLesson ? (
      <Modal
        backdropClassName="homeworkMakeupModalBackdrop"
        className="homeworkMakeupScheduleModal"
        title={`${followUpTypeLabel(selectedMakeupTask?.taskType)} 일정`}
        subtitle="일반 수업일지가 아니라, 원 수업 참고와 보충 처리를 분리해 확인하는 전용 화면입니다."
        onClose={onBackToCalendar}
      >
        <SupplementMakeupLessonDetail
          attendanceSettings={attendanceSettings}
          homeworks={homeworks}
          lesson={selectedLesson}
          lessons={lessons}
          onDeleteLesson={onDeleteLesson}
          onEditLesson={onEditLesson}
          onOpenAttendance={onOpenAttendance}
          onPassTask={onPassMakeupTask}
          onScheduleTask={onScheduleMakeupTask}
          onUpdateTask={onUpdateMakeupTask}
          records={records}
          students={students}
          task={selectedMakeupTask}
        />
      </Modal>
    ) : isExamPrepLessonSelected ? (
      <Modal
        backdropClassName="homeworkMakeupModalBackdrop"
        className="homeworkMakeupScheduleModal examPrepModal"
        title="시험대비"
        subtitle="시험기간 전후로 별도 개설한 시험대비 수업입니다."
        onClose={onBackToCalendar}
      >
        <ExamPrepLessonDetail
          lesson={selectedLesson}
          onDeleteLesson={onDeleteLesson}
          onEditLesson={onEditLesson}
        />
      </Modal>
    ) : (
      <Modal
        backdropClassName="lessonJournalModalBackdrop"
        className="lessonJournalModal"
        hideHeader
        onClose={onBackToCalendar}
      >
        <LessonJournalErrorBoundary
          key={selectedLesson.lessonId}
          fallback={(error) => (
            <LessonJournalFallback
              error={error}
              lesson={selectedLesson}
              onBack={onBackToCalendar}
              onDeleteLesson={onDeleteLesson}
              onEditLesson={onEditLesson}
              students={students}
            />
          )}
        >
          <LessonJournalDetail
            academyReminders={academyReminders}
            academyTests={academyTests}
            aiSettings={aiSettings}
            allRecords={allRecords}
            attendanceSettings={attendanceSettings}
            integrationStatus={integrationStatus}
            lessonNotificationPlan={lessonNotificationPlans[selectedLesson.lessonId] ?? { mode: "default" }}
            notificationJobs={notificationJobs}
            homeworks={homeworks}
            lesson={selectedLesson}
            lessons={lessons}
            materials={materials}
            makeupTasks={makeupTasks}
            onBack={onBackToCalendar}
            onCancelNotificationJob={onCancelNotificationJob}
            onChangeRecord={onChangeRecord}
            onDeleteLesson={onDeleteLesson}
            onEditLesson={onEditLesson}
            onOpenAttendance={onOpenAttendance}
            onOpenExamPrep={onOpenExamPrep}
            onOpenReport={onOpenReport}
            onPassMakeupTask={onPassMakeupTask}
            onPolishComment={onPolishComment}
            onReconcileSolapiNotificationResults={onReconcileSolapiNotificationResults}
            onApplyLessonNotificationPlan={onApplyLessonNotificationPlan}
            onSaveRecord={onSaveRecord}
            onSaveLessonJournalDrafts={onSaveLessonJournalDrafts}
            onScheduleMakeupTask={onScheduleMakeupTask}
            onScheduleLessonNotificationsAt={onScheduleLessonNotificationsAt}
            onSendComment={onSendComment}
            onUpdateHomework={onUpdateHomework}
            onUpdateLessonNotificationPlan={onUpdateLessonNotificationPlan}
            onUpdateMakeupTask={onUpdateMakeupTask}
            onToggleStudentNotificationMute={onToggleStudentNotificationMute}
            records={records}
            saveStates={saveStates}
            students={students}
            templates={templates}
            testAttempts={testAttempts}
            testSessions={testSessions}
          />
        </LessonJournalErrorBoundary>
      </Modal>
    )
  ) : null;
  const lessonTypeFilterOptions = [
    { id: "all", label: "전체" },
    { id: "regular", label: "정규수업" },
    { id: "preExam", label: "직전수업" },
    { id: "makeup", label: "보충수업" },
    { id: "examPrep", label: "시험대비" },
    { id: "specialLecture", label: "특강" }
  ];
  const visibleLessons = lessons.filter((lesson) => {
    if (isLegacyExamPrepLesson(lesson)) return false;
    if (lessonTypeFilter === "all") return true;
    if (lessonTypeFilter === "regular") return !["preExam", "makeup", "specialLecture"].includes(lesson.lessonType) && !isExamPrepLesson(lesson);
    if (lessonTypeFilter === "examPrep") return isExamPrepLesson(lesson);
    return lesson.lessonType === lessonTypeFilter;
  });
  const visibleLessonCount = visibleLessons.filter((lesson) => lesson.date.slice(0, 7) === selectedDate.slice(0, 7)).length;
  const shouldShowGeneratedLessonSaveNotice = generatedLessonSaveStatus?.state && generatedLessonSaveStatus.state !== "idle";

  return (
    <>
      <AcademyReminderPanel
        onDeleteAcademyReminder={onDeleteAcademyReminder}
        onSaveAcademyReminder={onSaveAcademyReminder}
        reminders={academyReminders}
        selectedDate={selectedDate}
        students={students}
        templates={templates}
      />

      {shouldShowGeneratedLessonSaveNotice ? (
        <div className={`generatedLessonSaveNotice ${generatedLessonSaveStatus.state}`}>
          <span>{generatedLessonSaveStatus.message || "직전수업 자동 저장 상태를 확인해 주세요."}</span>
          {generatedLessonSaveStatus.state === "failed" ? (
            <button className="softButton compact" onClick={onRetryGeneratedLessonSave} type="button">
              다시 저장
            </button>
          ) : null}
        </div>
      ) : null}

      <header className="pageTop teacherCalendarTop">
        <button className="iconButton" onClick={() => onMoveDate(-30)} type="button">‹</button>
        <h1>{formatMonthTitle(selectedDate)}</h1>
        <button className="iconButton" onClick={() => onMoveDate(30)} type="button">›</button>
        <div className="lessonTypeFilterBar" aria-label="수업일지 일정 종류 필터">
          {lessonTypeFilterOptions.map((option) => (
            <button
              className={lessonTypeFilter === option.id ? "active" : ""}
              key={option.id}
              onClick={() => setLessonTypeFilter(option.id)}
              type="button"
            >
              {option.label}
            </button>
          ))}
          <span>{visibleLessonCount}개</span>
        </div>
        <button className="primaryButton" onClick={onAddLesson} type="button">+ 수업 등록</button>
      </header>

      <section className="calendarShell teacherCalendarShell">
        <div className="calendarGrid teacherCalendarGrid">
          {["일", "월", "화", "수", "목", "금", "토"].map((label) => (
            <div className="weekday" key={label}>{label}</div>
          ))}
          {buildMonthDays(selectedDate).map((day) => {
            const dayLessons = visibleLessons.filter((lesson) => lesson.date === day.date).sort(sortByTime);
            return (
              <div
                className={[
                  "monthCell",
                  "teacherMonthCell",
                  day.inMonth ? "" : "outside",
                  selectedDate === day.date ? "selected" : ""
                ].join(" ")}
                key={day.date}
                onClick={() => onDateSelect(day.date)}
              >
                <span className="dayNumber">{day.dayNumber}</span>
                <span className="cellPlus">+</span>
                <span className="lessonPills">
                  {dayLessons.map((lesson) => {
                    const isExamPrepType = isExamPrepLesson(lesson);
                    const examPrepSourceLabel = isExamPrepType ? lesson.sourceLabel || "" : "";
                    return (
                      <button
                        className={[
                          "lessonPill",
                          lesson.lessonId === selectedLessonId ? "active" : "",
                          lesson.lessonType === "preExam" ? "preExamLessonPill" : "",
                          lesson.lessonType === "makeup" ? "makeupLessonPill" : "",
                          isExamPrepType ? "examPrepLessonPill" : "",
                          lesson.lessonType === "specialLecture" ? "specialLectureLessonPill" : ""
                        ].filter(Boolean).join(" ")}
                        key={lesson.lessonId}
                        onClick={(event) => {
                          event.stopPropagation();
                          onOpenLessonJournal(lesson.lessonId);
                        }}
                        style={{ background: lesson.color }}
                        type="button"
                      >
                        {lesson.startTime} {lesson.className}
                        {isExamPrepType
                          ? examPrepSourceLabel ? ` · ${examPrepSourceLabel}` : ""
                          : ` (${getLessonStudentIds(lesson).length}명)`}
                      </button>
                    );
                  })}
                </span>
              </div>
            );
          })}
        </div>
      </section>
      {lessonJournalDialog}
    </>
  );
}

function ExamPrepLessonDetail({ lesson, onDeleteLesson, onEditLesson }) {
  const sourceItems = String(lesson.sourceLabel || "")
    .split("·")
    .map((label) => label.trim())
    .filter(Boolean);
  const scheduledTime = `${lesson.date} ${lesson.startTime || "미정"}-${lesson.endTime || "미정"}`;
  const lessonStudentCount = getLessonStudentIds(lesson).length;

  return (
    <div className="examPrepLessonBody">
      <div className="examPrepSummaryGrid">
        <div>
          <span>수업일</span>
          <strong>{lesson.date}</strong>
          <small>시험대비</small>
        </div>
        <div>
          <span>시간</span>
          <strong>{lesson.startTime || "미정"}-{lesson.endTime || "미정"}</strong>
          <small>{lesson.status === "canceled" ? "취소됨" : "진행 예정"}</small>
        </div>
        <div>
          <span>참여 학생</span>
          <strong>{lessonStudentCount}명</strong>
          <small>{sourceItems.length ? `${sourceItems.length}개 시험정보 연결` : "시험정보 연결 없음"}</small>
        </div>
      </div>

      <section className="panel examPrepPanel">
        <div className="sectionHeader slim">
          <div>
            <span className="eyebrow">시험대비 수업</span>
            <h3>{lesson.lessonTopic || lesson.className || "시험대비"}</h3>
            <p className="muted">
              저장된 실제 수업 기준으로 수업일지와 알림톡을 연결합니다. 날짜나 시간이 다르면 일정 수정에서 이 수업 자체를 조정합니다.
            </p>
          </div>
          <div className="examPrepActions">
            <button className="ghostButton" onClick={() => onEditLesson(lesson)} type="button">
              일정 수정
            </button>
            <button className="dangerButton" onClick={() => onDeleteLesson(lesson.lessonId)} type="button">
              일정 삭제
            </button>
          </div>
        </div>

        {sourceItems.length ? (
          <div className="examPrepSourceList" aria-label="연결된 시험정보">
            {sourceItems.map((label) => (
              <div className="examPrepSourceItem" key={label}>
                <strong>{label}</strong>
                <small>{scheduledTime}</small>
              </div>
            ))}
          </div>
        ) : (
          <EmptyState as="p" className="examPrepEmptyState">연결된 시험정보가 없습니다. 필요한 경우 일정 수정에서 수업명과 학생 명단을 직접 정리하세요.</EmptyState>
        )}
      </section>
    </div>
  );
}

function SupplementMakeupLessonDetail({
  attendanceSettings = defaultAttendanceSettings,
  homeworks = [],
  lesson,
  lessons = [],
  onDeleteLesson,
  onEditLesson,
  onOpenAttendance,
  onPassTask,
  onScheduleTask,
  onUpdateTask,
  records = [],
  students = [],
  task
}) {
  const [passConfirmMode, setPassConfirmMode] = useState("");
  const [passSaveState, setPassSaveState] = useState({ message: "", mode: "", state: "idle" });
  const [isScheduleEditOpen, setIsScheduleEditOpen] = useState(false);
  const [scheduleDraft, setScheduleDraft] = useState({
    scheduleChangeDetail: "",
    scheduleChangeReason: "",
    scheduledDate: task?.scheduledDate || lesson.date || "",
    scheduledTime: task?.scheduledTime || lesson.startTime || ""
  });
  const [scheduleSaveState, setScheduleSaveState] = useState({ message: "", state: "idle" });
  const lessonStudents = getActiveLessonStudents(lesson, students);
  const student = lessonStudents[0] ?? students.find((item) => item.studentId === task?.studentId);
  const isAbsenceMakeup = task?.taskType === "absence_makeup";
  const taskLabel = followUpTypeLabel(task?.taskType);
  const targetHomework =
    homeworks.find((homework) => homework.homeworkId === task?.sourceId) ??
    homeworks.find(
      (homework) =>
        homework.studentId === student?.studentId &&
        homework.title === (task?.sourceLabel ?? lesson.sourceLabel)
    );
  const absenceSourceRecord = isAbsenceMakeup
    ? records.find((record) => record.lessonStudentRecordId === task?.sourceId) ??
      records.find((record) => record.lessonId === task?.sourceLessonId && record.studentId === student?.studentId)
    : null;
  const homeworkSourceLesson = targetHomework?.lessonId
    ? lessons.find((item) => item.lessonId === targetHomework.lessonId)
    : null;
  const sourceLesson = isAbsenceMakeup
    ? lessons.find((item) => item.lessonId === absenceSourceRecord?.lessonId) ??
      lessons.find((item) => item.lessonId === task?.sourceLessonId) ??
      null
    : homeworkSourceLesson;
  const sourceDate =
    sourceLesson?.date ||
    (isAbsenceMakeup ? task?.lessonDate : "") ||
    targetHomework?.assignedDate ||
    targetHomework?.startDate ||
    targetHomework?.date ||
    "기록 없음";
  const dueDate = isAbsenceMakeup
    ? sourceDate
    : targetHomework?.dueDate ?? targetHomework?.endDate ?? "기록 없음";
  const sourceLessonLabel = sourceLesson?.className ?? sourceLesson?.lessonTopic ?? "원 수업 기록";
  const sourcePreviousHomework = sourceLesson && student
    ? getLessonHomework(homeworks, sourceLesson, student, "previous", lessons)
    : null;
  const sourceNextHomework = sourceLesson && student
    ? getLessonHomework(homeworks, sourceLesson, student, "next", lessons)
    : null;
  const sourceLessonMaterial = absenceSourceRecord?.lessonMaterial || "";
  const sourceLessonContent = absenceSourceRecord
    ? getLessonContent(absenceSourceRecord)
    : "";
  const sourcePreviousHomeworkText =
    sourcePreviousHomework?.title ||
    absenceSourceRecord?.previousHomework ||
    task?.supplementHomeworkNote ||
    "";
  const sourceNextHomeworkText =
    sourceNextHomework?.title ||
    absenceSourceRecord?.nextHomework ||
    "";
  const targetTitle =
    getSupplementTaskSourceLabel(task) ||
    targetHomework?.title ||
    lesson.sourceLabel ||
    `${taskLabel} 대상`;
  const originalHomeworkTitle = targetHomework?.title || task?.sourceLabel || lesson.sourceLabel || "";
  const originalHomeworkHint =
    originalHomeworkTitle && originalHomeworkTitle !== targetTitle ? `원본 숙제명: ${originalHomeworkTitle}` : sourceLessonLabel;
  const supplementAttendanceLesson = lesson;
  const supplementAttendanceRecord = student
    ? findLessonStudentRecord(records, lesson, student) ?? createEmptyRecord(lesson, student)
    : null;
  const supplementAttendanceDisplay = student && supplementAttendanceRecord
    ? getAttendanceDisplay(supplementAttendanceRecord, supplementAttendanceLesson, attendanceSettings.lateGraceMinutes)
    : null;
  const supplementCheckoutMissing = student && supplementAttendanceRecord
    ? hasMissingCheckOut(supplementAttendanceRecord, supplementAttendanceLesson)
    : false;
  const isTaskDone = task?.status === "done" || (passSaveState.state === "saved" && passSaveState.mode === "completed");
  const isPassSaving = passSaveState.state === "saving";
  const statusLabel =
    isTaskDone ? "보충 완료" : task?.status === "scheduled" ? "일정 확정" : "일정 미확정";
  const scheduledText = `${lesson.date} ${lesson.startTime || ""}`.trim();
  const confirmedText = task?.lastScheduledAt ? formatKoreanDateTime(task.lastScheduledAt) : "확정 기록 없음";
  const completedText = task?.completedAt || task?.passedAt ? formatKoreanDateTime(task.completedAt || task.passedAt) : "";
  const processStatus = isTaskDone ? "completed" : task?.supplementProcessStatus || "in_progress";
  const processMemo = task?.supplementProgressMemo || "";
  const nextSupplementPlan = task?.nextSupplementPlan || "";
  const passStateMessage =
    passSaveState.message ||
    (task?.status === "done"
      ? `보충 완료 처리 완료${completedText ? ` · ${completedText}` : ""}. 보충관리 active 목록에서는 제외됩니다.`
      : "");
  const normalizedScheduleDraftTime = normalizeTimeInput(scheduleDraft.scheduledTime) || scheduleDraft.scheduledTime;
  const canSaveScheduleDraft = Boolean(onScheduleTask && task?.makeupTaskId && scheduleDraft.scheduledDate && scheduleDraft.scheduledTime);
  const isScheduleSaving = scheduleSaveState.state === "saving";

  useEffect(() => {
    setScheduleDraft({
      scheduleChangeDetail: getSupplementScheduleChangeDetailSeed(task) || targetTitle,
      scheduleChangeReason: "",
      scheduledDate: task?.scheduledDate || lesson.date || "",
      scheduledTime: task?.scheduledTime || lesson.startTime || ""
    });
    setScheduleSaveState({ message: "", state: "idle" });
    setPassSaveState({ message: "", mode: "", state: "idle" });
    setIsScheduleEditOpen(false);
  }, [lesson.lessonId, task?.makeupTaskId]);

  function updateTaskField(field, value) {
    if (!task?.makeupTaskId || !onUpdateTask) return;
    onUpdateTask(task.makeupTaskId, field, value);
  }

  function handleProcessStatusChange(nextStatus) {
    updateTaskField("supplementProcessStatus", nextStatus);
    if (nextStatus === "needs_more") {
      updateTaskField("status", "scheduled");
    }
  }

  async function confirmPassTask() {
    if (!task || !onPassTask) return;
    const isNeedsMore = passConfirmMode === "needs_more";
    const completedMemo = [
      processMemo,
      isNeedsMore && nextSupplementPlan ? `추가 보충 필요: ${nextSupplementPlan}` : ""
    ].filter(Boolean).join("\n");
    setPassSaveState({
      message: isNeedsMore ? "추가 보충 필요 상태로 저장하는 중입니다." : "보충 완료 처리 중입니다.",
      mode: isNeedsMore ? "needs_more" : "completed",
      state: "saving"
    });
    try {
      const savedTask = await onPassTask({
        ...task,
        supplementProcessStatus: isNeedsMore ? "needs_more" : "completed",
        supplementProgressMemo: completedMemo,
        nextSupplementPlan: isNeedsMore ? nextSupplementPlan : task.nextSupplementPlan || "",
        completionDecision: isNeedsMore ? "needs_more" : "completed"
      });
      const savedAt = savedTask?.completedAt || savedTask?.passedAt ? formatKoreanDateTime(savedTask.completedAt || savedTask.passedAt) : "";
      setPassConfirmMode("");
      setPassSaveState({
        message: isNeedsMore
          ? "추가 보충 필요로 저장했습니다. 보충관리 목록에 계속 남습니다."
          : `보충 완료 처리 완료${savedAt ? ` · ${savedAt}` : ""}. 보충관리 active 목록에서는 제외됩니다.`,
        mode: isNeedsMore ? "needs_more" : "completed",
        state: "saved"
      });
    } catch (error) {
      setPassSaveState({
        message: error?.message || "보충 완료 처리를 저장하지 못했습니다.",
        mode: isNeedsMore ? "needs_more" : "completed",
        state: "failed"
      });
    }
  }

  async function saveScheduleDraft(updateStudentReminder) {
    if (!task?.makeupTaskId) {
      setScheduleSaveState({ message: "연결된 보충관리 항목을 찾지 못해 일정을 저장할 수 없습니다.", state: "failed" });
      return;
    }
    if (!scheduleDraft.scheduledDate || !scheduleDraft.scheduledTime) {
      setScheduleSaveState({ message: "배정일과 시간을 먼저 입력해주세요.", state: "failed" });
      return;
    }
    if (!onScheduleTask) {
      setScheduleSaveState({ message: "보충관리 일정 저장 경로가 연결되어 있지 않습니다.", state: "failed" });
      return;
    }

    setScheduleSaveState({
      message: updateStudentReminder
        ? "일정, 학생·학부모 다음 정각 안내, 학생 11시 알림톡 예약을 함께 갱신하는 중입니다."
        : "일정만 저장하는 중입니다. 학생 11시 알림톡 예약은 변경하지 않습니다.",
      state: "saving"
    });

    try {
      const result = await onScheduleTask({
        ...task,
        keepLessonJournalOpen: true,
        scheduleChangeDetail: scheduleDraft.scheduleChangeDetail,
        scheduleChangeReason: scheduleDraft.scheduleChangeReason,
        scheduledDate: scheduleDraft.scheduledDate,
        scheduledTime: normalizedScheduleDraftTime,
        skipStudentReminder: !updateStudentReminder
      });
      const nextTask = result?.makeupTask ?? {
        ...task,
        scheduleChangeDetail: scheduleDraft.scheduleChangeDetail,
        scheduleChangeReason: "",
        scheduledDate: scheduleDraft.scheduledDate,
        scheduledTime: normalizedScheduleDraftTime
      };
      const savedChangeDetail = Object.prototype.hasOwnProperty.call(nextTask, "scheduleChangeDetail")
        ? nextTask.scheduleChangeDetail
        : scheduleDraft.scheduleChangeDetail || getSupplementScheduleChangeDetailSeed(nextTask);
      setScheduleDraft({
        scheduleChangeDetail: savedChangeDetail,
        scheduleChangeReason: "",
        scheduledDate: nextTask.scheduledDate || scheduleDraft.scheduledDate,
        scheduledTime: nextTask.scheduledTime || normalizedScheduleDraftTime
      });
      setScheduleSaveState({
        message: updateStudentReminder
          ? [
              result?.scheduleChangeNoticeSkipped ? "" : result?.scheduleChangeNoticeMessage,
              result?.parentScheduleChangeNoticeSkipped ? "" : result?.parentScheduleChangeNoticeMessage,
              result?.supplementReminderMessage || "학생 11시 알림톡 예약을 갱신했습니다."
            ].filter(Boolean).join(" ")
          : result?.supplementReminderMessage || "일정만 저장했습니다. 학생 11시 알림톡 예약은 변경하지 않았습니다.",
        state: "saved"
      });
    } catch (error) {
      setScheduleSaveState({
        message: error?.message || "보충 일정을 저장하지 못했습니다.",
        state: "failed"
      });
    }
  }

  return (
    <div className="homeworkMakeupModalBody">
      <div className="homeworkMakeupSummary">
        <div>
          <span>대상 학생</span>
          <strong>{student?.name ?? "미확인"}</strong>
          <small>{student?.grade ?? "-"} · {student?.schoolName ?? student?.school ?? "학교 미입력"}</small>
        </div>
        <div>
          <span>{isAbsenceMakeup ? "결석한 수업" : "해야 했던 날짜"}</span>
          <strong>{dueDate}</strong>
          <small>{isAbsenceMakeup ? sourceLessonLabel : `${sourceDate} 배정`}</small>
        </div>
        <div>
          <span>{isAbsenceMakeup ? "결석 보강 내용" : "안 한 숙제 내용"}</span>
          <strong>{targetTitle}</strong>
          <small>{isAbsenceMakeup ? task?.absenceReason || "결석 사유 미입력" : originalHomeworkHint}</small>
        </div>
        <div>
          <span>보충 확정 일정</span>
          <strong>{scheduledText}</strong>
          <small>확정 처리: {confirmedText}</small>
        </div>
      </div>

      <div className="homeworkMakeupModalActions">
        <span className="statusPill">{statusLabel}</span>
        <div>
          <button className="ghostButton scheduleEditButton" type="button" onClick={() => setIsScheduleEditOpen((current) => !current)}>
            {isScheduleEditOpen ? "수정 닫기" : "일정 수정"}
          </button>
          <button className="dangerButton" type="button" onClick={() => onDeleteLesson(lesson.lessonId)}>
            일정 삭제
          </button>
        </div>
      </div>

      {isScheduleEditOpen ? (
        <section className="homeworkMakeupScheduleEditor" aria-label="숙제보충 일정 수정">
          <div>
            <strong>보충 일정 수정</strong>
            <span>저장하면 보충관리와 수업일지 일정이 함께 갱신됩니다. 솔라피 발송과 예약 갱신 여부는 아래에서 선택합니다.</span>
          </div>
          <div className="fieldGrid two">
            <label>
              <strong>배정일</strong>
              <input
                type="date"
                value={scheduleDraft.scheduledDate}
                onChange={(event) => setScheduleDraft((current) => ({ ...current, scheduledDate: event.target.value }))}
              />
            </label>
            <label>
              <strong>시간</strong>
              <input
                type="time"
                value={scheduleDraft.scheduledTime}
                onChange={(event) => setScheduleDraft((current) => ({ ...current, scheduledTime: event.target.value }))}
              />
            </label>
          </div>
          <div className="fieldGrid two">
            <label className="homeworkMakeupScheduleTextField">
              <strong>보충 내역</strong>
              <textarea
                value={scheduleDraft.scheduleChangeDetail}
                onChange={(event) => setScheduleDraft((current) => ({ ...current, scheduleChangeDetail: event.target.value }))}
                placeholder="예: 쎈 C단계, 지난 숙제 확인, 결석 수업 보강 범위"
              />
            </label>
            <label className="homeworkMakeupScheduleTextField">
              <strong>변경 사유</strong>
              <textarea
                value={scheduleDraft.scheduleChangeReason}
                onChange={(event) => setScheduleDraft((current) => ({ ...current, scheduleChangeReason: event.target.value }))}
                placeholder="예: 학생 요청, 수업 시간 조정, 개인 일정 변경"
              />
            </label>
          </div>
          {scheduleSaveState.message ? (
            <p className={`homeworkMakeupScheduleState ${scheduleSaveState.state}`}>{scheduleSaveState.message}</p>
          ) : null}
          <div className="modalActions supplementSplitActions">
            <button className="softButton" disabled={!canSaveScheduleDraft || isScheduleSaving} onClick={() => saveScheduleDraft(false)} type="button">
              {isScheduleSaving ? "저장 중" : "일정만 저장"}
            </button>
            <button className="softButton scheduleApplyButton" disabled={!canSaveScheduleDraft || isScheduleSaving} onClick={() => saveScheduleDraft(true)} type="button">
              {isScheduleSaving ? "예약/갱신 중" : "다음 정각 예약 및 11시 갱신"}
            </button>
          </div>
          <p className="supplementScheduleActionHint">
            현재 일정의 학생·학부모 안내가 없으면 다음 정각으로 예약하고, 보강 당일 오전 11시 학생 알림톡 예약도 갱신합니다. 이미 같은 일정 안내가 있으면 중복 예약하지 않습니다.
          </p>
        </section>
      ) : null}

      <div className="homeworkMakeupHero">
        <section className="panel homeworkMakeupNotice">
          <h3>{isAbsenceMakeup ? "원 결석 수업" : "보충 대상"}</h3>
          <div className="makeupLinkedBox">
            <span>{isAbsenceMakeup ? "결석한 수업" : "보충 대상"}</span>
            <strong>{targetTitle}</strong>
            <small>{isAbsenceMakeup ? `원 결석 수업일: ${sourceDate}` : `원 수업일자: ${sourceDate} · 마감일: ${dueDate}`}</small>
            {!isAbsenceMakeup && originalHomeworkTitle && originalHomeworkTitle !== targetTitle ? (
              <small className="makeupOriginalHomework">수업일지 원본 숙제명: {originalHomeworkTitle}</small>
            ) : null}
          </div>
          {student && supplementAttendanceRecord ? (
            <div className="supplementAttendanceBox">
              <div>
                <span>보충 당일 출결</span>
                <strong>{lesson.date} {lesson.startTime || ""}</strong>
                <small>출결 저장/알림톡은 이 보충 수업의 lessonId 기준으로 처리됩니다.</small>
              </div>
              <button
                className={`attendanceBadge attendance-${supplementAttendanceDisplay?.statusClass ?? supplementAttendanceRecord.attendanceStatus ?? "pending"}`}
                disabled={!onOpenAttendance}
                onClick={() => onOpenAttendance?.({ lesson: supplementAttendanceLesson, record: supplementAttendanceRecord, student })}
                type="button"
              >
                <span>{supplementAttendanceDisplay?.label ?? "출결 입력"}</span>
                {supplementAttendanceDisplay?.detail ? <small>{supplementAttendanceDisplay.detail}</small> : null}
                {supplementCheckoutMissing ? <small className="checkoutMissingText">하원 미체크</small> : null}
              </button>
            </div>
          ) : null}
          {isAbsenceMakeup ? (
            <div className="absenceSourceJournalBox compact">
              <h4>원 결석 수업 맥락</h4>
              <p className="muted">오늘 보충 수업의 이전/다음 숙제가 아니라, 결석했던 수업의 저장본입니다.</p>
              <div className="absenceSourceJournalGrid compact">
                <div>
                  <span>그날 수업 교재</span>
                  <strong>{sourceLessonMaterial || "기록 없음"}</strong>
                </div>
                <div>
                  <span>그날 수업 내용</span>
                  <strong>{sourceLessonContent || "기록 없음"}</strong>
                </div>
                <div>
                  <span>그날 확인할 지난 숙제</span>
                  <strong>{sourcePreviousHomeworkText || "기록 없음"}</strong>
                </div>
                <div>
                  <span>그날 새로 나간 숙제</span>
                  <strong>{sourceNextHomeworkText || "기록 없음"}</strong>
                </div>
              </div>
            </div>
          ) : null}
        </section>
        <section className="panel homeworkMakeupProcess">
          <div className="sectionHeader slim">
            <div>
              <h3>보충 처리</h3>
              <p className="muted">오늘 무엇을 보충했고, 남은 보충이 있는지 기록합니다.</p>
            </div>
          </div>
          <div className="makeupProcessStatusGrid">
            {[
              { id: "in_progress", label: "진행 중", description: "보충을 진행했지만 아직 완료 판단 전" },
              { id: "needs_more", label: "추가 보충 필요", description: "오늘 다 끝나지 않아 다음 보충이 필요" },
              { id: "completed", label: "보충 완료", description: "이번 보충 항목을 통과 처리 가능" }
            ].map((option) => (
              <button
                className={processStatus === option.id ? "active" : ""}
                disabled={isPassSaving || isTaskDone}
                key={option.id}
                onClick={() => handleProcessStatusChange(option.id)}
                type="button"
              >
                <strong>{option.label}</strong>
                <span>{option.description}</span>
              </button>
            ))}
          </div>
          <div className="makeupProcessFormGrid">
            <label className="makeupProcessField">
              보충 진행 메모
              <textarea
                disabled={isPassSaving || isTaskDone}
                value={processMemo}
                onChange={(event) => updateTaskField("supplementProgressMemo", event.target.value)}
                placeholder="예: 쎈 오답 5문항 중 3문항 풀이 완료. 나머지 2문항은 계산 실수 반복으로 추가 확인 필요."
              />
            </label>
            <label className="makeupProcessField">
              추가 보충 내용
              <textarea
                disabled={isPassSaving || isTaskDone}
                value={nextSupplementPlan}
                onChange={(event) => updateTaskField("nextSupplementPlan", event.target.value)}
                placeholder="추가 보충이 필요할 때 다음에 진행할 숙제/문항/범위를 적어주세요."
              />
            </label>
          </div>
          {passStateMessage ? (
            <p className={`homeworkMakeupPassState ${passSaveState.state === "idle" && task?.status === "done" ? "saved" : passSaveState.state}`}>
              {passStateMessage}
            </p>
          ) : null}
          <div className="makeupProcessActions">
            <button className="softButton" disabled={isPassSaving || isTaskDone} onClick={() => setPassConfirmMode("needs_more")} type="button">
              {isPassSaving ? "처리 중" : "추가 보충 필요로 기록"}
            </button>
            <button className="passButton" disabled={!task || isTaskDone || isPassSaving} onClick={() => setPassConfirmMode("completed")} type="button">
              {isTaskDone ? "보충 완료됨" : isPassSaving ? "처리 중" : "보충 완료 처리"}
            </button>
          </div>
        </section>
      </div>
      {passConfirmMode ? (
        <Modal
          className="supplementPassConfirmModal"
          title={passConfirmMode === "needs_more" ? "추가 보충 필요 기록" : "보충 완료 처리"}
          subtitle="처리 내용은 보충관리 이력에 남습니다."
          onClose={() => {
            if (!isPassSaving) setPassConfirmMode("");
          }}
        >
          <div className="supplementPassConfirmBody">
            <p>
              <strong>{student?.name ?? "학생"}</strong> 학생의 보충을
              {passConfirmMode === "needs_more" ? " 추가 보충 필요 상태로 기록할까요?" : " 완료 처리할까요?"}
            </p>
            <dl className="supplementPassConfirmSummary">
              <div>
                <dt>보충 대상</dt>
                <dd>{targetTitle}</dd>
              </div>
              <div>
                <dt>진행 메모</dt>
                <dd>{processMemo || "메모 없음"}</dd>
              </div>
              {passConfirmMode === "needs_more" ? (
                <div>
                  <dt>추가 내용</dt>
                  <dd>{nextSupplementPlan || "추가 보충 내용을 입력하지 않았습니다."}</dd>
                </div>
              ) : null}
            </dl>
          </div>
          <div className="modalActions confirmActions">
            <button className="softButton" disabled={isPassSaving} onClick={() => setPassConfirmMode("")} type="button">
              취소
            </button>
            <button className="passButton" disabled={isPassSaving} onClick={confirmPassTask} type="button">
              {isPassSaving ? "처리 중" : passConfirmMode === "needs_more" ? "추가 보충 필요 기록" : "보충 완료 처리"}
            </button>
          </div>
          {passSaveState.message ? (
            <p className={`homeworkMakeupPassState modalState ${passSaveState.state}`}>{passSaveState.message}</p>
          ) : null}
        </Modal>
      ) : null}
    </div>
  );
}

function EditableMemoCard({ className = "", disabled = false, editKey, editingKey, onChange, onEdit, placeholder, value }) {
  const textareaRef = useRef(null);
  const isEditable = !disabled;
  const shouldFocus = isEditable && editingKey === editKey;
  const displayValue = value?.trim() ? value : "";

  useEffect(() => {
    if (!isEditable || !textareaRef.current) return;
    const textarea = textareaRef.current;
    textarea.style.height = "auto";
    textarea.style.height = `${textarea.scrollHeight}px`;
    if (shouldFocus) textarea.focus();
  }, [isEditable, shouldFocus, value]);

  function handleChange(event) {
    const textarea = event.target;
    textarea.style.height = "auto";
    textarea.style.height = `${textarea.scrollHeight}px`;
    onChange(textarea.value);
  }

  if (isEditable) {
    return (
      <textarea
        className={`journalMemoCardInput ${className}`.trim()}
        onChange={handleChange}
        onFocus={() => onEdit(editKey)}
        onKeyDown={(event) => {
          if (event.key === "Escape" || (event.key === "Enter" && (event.ctrlKey || event.metaKey))) {
            event.currentTarget.blur();
          }
        }}
        placeholder={placeholder}
        ref={textareaRef}
        rows="1"
        value={value ?? ""}
      />
    );
  }

  return (
    <button
      className={`journalMemoCardRead ${displayValue ? "" : "empty"} ${disabled ? "locked" : ""} ${className}`.trim()}
      onClick={() => {
        if (!disabled) onEdit(editKey);
      }}
      type="button"
    >
      {displayValue || placeholder}
    </button>
  );
}

function LessonJournalFallback({ error, lesson, onBack, onDeleteLesson, onEditLesson, students = [] }) {
  const lessonStudents = getActiveLessonStudents(lesson, students);
  return (
    <section className="lessonJournalPage">
      <header className="pageTop lessonJournalHeader">
        <button className="iconButton" onClick={onBack} type="button">‹</button>
        <div>
          <h2>{lesson?.className || "수업일지"}</h2>
          <p className="muted">{lesson?.date || "-"} · {lesson?.startTime || ""}-{lesson?.endTime || ""} · {lessonStudents.length}명</p>
        </div>
        <button className="softButton" onClick={() => onEditLesson?.(lesson)} type="button">수업 수정</button>
        <button className="dangerButton" onClick={() => onDeleteLesson?.(lesson.lessonId)} type="button">수업 취소 처리</button>
      </header>
      <section className="panel lessonJournalFallback">
        <strong>수업일지를 여는 중 오류가 발생했습니다.</strong>
        <p>수업 정보는 저장되어 있습니다. 수업 수정에서 학생과 시간을 확인한 뒤 다시 열어 주세요.</p>
        {lessonStudents.length > 0 ? (
          <div className="studentChips">
            {lessonStudents.map((student) => (
              <span className="lessonStudentChip selected" key={student.studentId}>{student.name}</span>
            ))}
          </div>
        ) : (
          <p className="muted">이 수업에 표시할 학생을 찾지 못했습니다.</p>
        )}
        <small>{String(error?.message ?? error ?? "알 수 없는 오류")}</small>
      </section>
    </section>
  );
}

function LessonJournalDetail({
  academyReminders = [],
  academyTests = [],
  aiSettings = defaultAiSettings,
  allRecords = [],
  attendanceSettings = defaultAttendanceSettings,
  integrationStatus,
  homeworks = [],
  lesson,
  lessonNotificationPlan = { mode: "default" },
  lessons,
  materials = [],
  makeupTasks = [],
  onBack,
  onCancelNotificationJob,
  onChangeRecord,
  onDeleteLesson,
  onEditLesson,
  onOpenAttendance,
  onOpenExamPrep,
  onOpenReport,
  onPassMakeupTask,
  onPolishComment,
  onReconcileSolapiNotificationResults,
  onApplyLessonNotificationPlan,
  onSaveRecord,
  onSaveLessonJournalDrafts,
  onScheduleMakeupTask,
  onScheduleLessonNotificationsAt,
  onSendComment,
  onUpdateHomework,
  onUpdateLessonNotificationPlan,
  onUpdateMakeupTask,
  onToggleStudentNotificationMute,
  notificationJobs = [],
  records,
  saveStates,
  students,
  templates = [],
  testAttempts = [],
  testSessions = []
}) {
  const [commentModal, setCommentModal] = useState(null);
  const [prepMemoModal, setPrepMemoModal] = useState(null);
  const [journalEditMode, setJournalEditMode] = useState(false);
  const [journalRecordDrafts, setJournalRecordDrafts] = useState({});
  const [journalHomeworkDrafts, setJournalHomeworkDrafts] = useState({});
  const [journalMakeupTaskDrafts, setJournalMakeupTaskDrafts] = useState({});
  const [journalManualSaveMessage, setJournalManualSaveMessage] = useState("");
  const [reservationModalOpen, setReservationModalOpen] = useState(false);
  const [reservationAudit, setReservationAudit] = useState({
    message: "",
    osJobs: null,
    solapiGroups: [],
    solapiMessages: [],
    state: "idle"
  });
  const [reservationInspectMode, setReservationInspectMode] = useState("all");
  const [cancelingReservationJobId, setCancelingReservationJobId] = useState("");
  const [cancelingSolapiGroupId, setCancelingSolapiGroupId] = useState("");
  const [reservationApplyState, setReservationApplyState] = useState("idle");
  const [solapiResultRefreshState, setSolapiResultRefreshState] = useState("idle");
  const [editingMemoKey, setEditingMemoKey] = useState("");
  const [studentPreviewId, setStudentPreviewId] = useState("");
  const commentAiProvider = aiSettings.commentProvider ?? defaultAiSettings.commentProvider;
  const commentAiModel = aiSettings.commentModel ?? defaultAiSettings.commentModel;
  const linkedMakeupTask = makeupTasks.find((task) => task.makeupTaskId === lesson.sourceMakeupTaskId || task.linkedLessonId === lesson.lessonId);
  const notificationPlanMode = lessonNotificationPlan?.mode || "default";
  const defaultAlimtalkTimeLabel = formatKoreaTimeLabel(getLessonAlimtalkScheduledDate(lesson, 0, { allowPastFallback: false }));
  const delayedAlimtalkTimeLabel = formatKoreaTimeLabel(getLessonAlimtalkScheduledDate(lesson, 30, { allowPastFallback: false }));
  const isDefaultScheduleExpired = isLessonAlimtalkScheduleExpired(lesson, 0);
  const isDelayedScheduleExpired = isLessonAlimtalkScheduleExpired(lesson, 30);
  const lessonNotificationJobs = notificationJobs.filter((job) => job.lessonId === lesson.lessonId);
  const auditedLessonNotificationJobs = Array.isArray(reservationAudit.osJobs) ? reservationAudit.osJobs : lessonNotificationJobs;
  const todayTwoPmIso = new Date(`${today}T14:00:00+09:00`).toISOString();
  const canScheduleTodayTwoPm = lesson.date < today && Boolean(onScheduleLessonNotificationsAt);
  const lessonStudents = getActiveLessonStudents(lesson, students);
  const lessonAcademyReminders = getAcademyRemindersForLesson(academyReminders, lesson, lessonStudents);
  const lessonStudentIdSet = new Set(lessonStudents.map((student) => student.studentId));
  const scheduledParentCount = auditedLessonNotificationJobs.filter((job) => job.notificationType === "parent_comment" && job.status === "scheduled").length;
  const scheduledStudentCount = auditedLessonNotificationJobs.filter((job) => job.notificationType === "student_comment" && job.status === "scheduled").length;
  const sentParentCount = auditedLessonNotificationJobs.filter((job) => job.notificationType === "parent_comment" && job.status === "sent").length;
  const sentStudentCount = auditedLessonNotificationJobs.filter((job) => job.notificationType === "student_comment" && job.status === "sent").length;
  const canceledJobCount = auditedLessonNotificationJobs.filter((job) => job.status === "canceled").length;
  const failedJobCount = auditedLessonNotificationJobs.filter((job) => job.status === "failed").length;
  const orphanScheduledJobs = auditedLessonNotificationJobs
    .filter((job) => canCancelNotificationJob(job) && job.studentId && !lessonStudentIdSet.has(job.studentId))
    .sort(sortNotificationJobsForCurrentStatus);
  const solapiLessonMessages = reservationAudit.solapiMessages.filter((message) => {
    if (message.customFields?.lessonId === lesson.lessonId) return true;
    const messageTo = normalizePhoneNumber(Array.isArray(message.to) ? message.to[0] : message.to);
    if (!messageTo) return false;
    return lessonStudents.some((student) =>
      [student.parentPhone, student.studentPhone].some((phone) => normalizePhoneNumber(phone) === messageTo)
    );
  });
  const solapiScheduledGroups = reservationAudit.solapiGroups.filter((group) =>
    group.scheduledDate && !group.dateSent && !group.dateCompleted && group.status !== "CANCELED"
  );
  const issueReservationJobs = auditedLessonNotificationJobs
    .filter((job) => job.status === "canceled" || job.status === "failed")
    .sort(sortNotificationJobsForCurrentStatus);
  const reservationInspectLabels = {
    all: "전체 예약",
    issues: "취소/실패",
    parentScheduled: "OS 학부모 예약",
    solapiScheduled: "Solapi 예약 그룹",
    studentScheduled: "OS 학생 예약"
  };
  const displayedSolapiGroups = reservationInspectMode === "solapiScheduled"
    ? solapiScheduledGroups
    : reservationAudit.solapiGroups;
  const displayedSolapiMessages = reservationInspectMode === "solapiScheduled"
    ? solapiLessonMessages.filter((message) => {
        const groupId = message.groupId || message.group?.groupId || message.customFields?.groupId;
        return !groupId || solapiScheduledGroups.some((group) => group.groupId === groupId);
      })
    : solapiLessonMessages;
  const shouldShowStudentReservationTable = reservationInspectMode !== "solapiScheduled";
  const shouldShowSolapiAudit = reservationInspectMode === "all" || reservationInspectMode === "solapiScheduled";
  const shouldShowIssueAudit = reservationInspectMode === "issues";
  const lessonRecordSaveStates = lessonStudents
    .map((student) => saveStates[createLessonStudentRecordId(lesson.lessonId, student.studentId)])
    .filter(Boolean);
  const lessonJournalSaveStatus = (() => {
    if (lessonRecordSaveStates.includes("saving")) return { label: "저장 중...", tone: "saving" };
    if (lessonRecordSaveStates.includes("dirty")) return { label: "저장 대기...", tone: "dirty" };
    if (lessonRecordSaveStates.includes("failed")) return { label: "저장 실패", tone: "failed" };
    if (lessonRecordSaveStates.includes("saved")) return { label: "저장 완료", tone: "saved" };
    return { label: "", tone: "idle" };
  })();
  const defaultScheduleHintText = isDefaultScheduleExpired
    ? `기본 예약 시간 지남 · ${defaultAlimtalkTimeLabel}`
    : `기본 예약 ${defaultAlimtalkTimeLabel}`;
  const isLessonNotificationOff = notificationPlanMode === "none";
  const checkoutMissingStudents = lessonStudents.filter((student) => {
    const record = findLessonStudentRecord(records, lesson, student);
    const attendanceLesson = applyStudentScheduleToLesson(lesson, student);
    return hasMissingCheckOut(record, attendanceLesson);
  });
  const isSupplementMakeupLesson = isSupplementMakeupTaskLesson(lesson, linkedMakeupTask);
  const isExamPrepLessonCurrent = isExamPrepLesson(lesson);

  useEffect(() => {
    setJournalEditMode(false);
    setJournalRecordDrafts({});
    setJournalHomeworkDrafts({});
    setJournalMakeupTaskDrafts({});
    setJournalManualSaveMessage("");
    setReservationApplyState("idle");
    setSolapiResultRefreshState("idle");
  }, [lesson.lessonId]);

  useEffect(() => {
    setReservationApplyState("idle");
  }, [lessonNotificationPlan?.mode, lessonNotificationPlan?.scheduledAt]);

  const journalRecordDraftCount = Object.keys(journalRecordDrafts).length;
  const journalHomeworkDraftCount = Object.keys(journalHomeworkDrafts).length;
  const journalMakeupTaskDraftCount = Object.keys(journalMakeupTaskDrafts).length;
  const hasJournalDraftChanges = journalRecordDraftCount > 0 || journalHomeworkDraftCount > 0 || journalMakeupTaskDraftCount > 0;
  const journalDraftChangeCount = journalRecordDraftCount + journalHomeworkDraftCount + journalMakeupTaskDraftCount;
  const journalStickySaveState = journalManualSaveMessage.includes("저장 실패")
    ? "failed"
    : journalManualSaveMessage.includes("저장 중")
      ? "saving"
      : hasJournalDraftChanges
        ? "dirty"
        : journalManualSaveMessage.includes("저장 완료")
          ? "saved"
          : lessonJournalSaveStatus.tone;
  const journalStickySaveMessage = hasJournalDraftChanges
    ? `저장 전 변경 ${journalDraftChangeCount}건`
    : journalManualSaveMessage || lessonJournalSaveStatus.label || "편집을 시작하면 변경 내용이 여기에 표시됩니다.";
  const activeLessonReservationJobs = lessonNotificationJobs.filter(isActiveNotificationJobStatus);
  const solapiResultRefreshTargetJobs = auditedLessonNotificationJobs.filter((job) =>
    job.provider === "solapi" &&
    getNotificationJobProviderReference(job) &&
    (job.status === "send_unconfirmed" || (job.status === "scheduled" && isNotificationSchedulePast(job.scheduledAt, 0)))
  );
  const completedSolapiResultJobs = auditedLessonNotificationJobs.filter((job) =>
    job.provider === "solapi" &&
    getNotificationJobProviderReference(job) &&
    job.status === "sent"
  );
  const failedSolapiResultJobs = auditedLessonNotificationJobs.filter((job) =>
    job.provider === "solapi" &&
    getNotificationJobProviderReference(job) &&
    job.status === "failed"
  );
  const hasSolapiResultRefreshTarget = solapiResultRefreshTargetJobs.length > 0;

  function getExpectedSolapiReservationItems() {
    if (notificationPlanMode === "none") return [];
    const scheduledDate = notificationPlanMode === "manual"
      ? lessonNotificationPlan?.scheduledAt
      : getLessonAlimtalkScheduledDate(lesson, notificationPlanMode === "delay30" ? 30 : 0, { allowPastFallback: false });
    if (!scheduledDate) return [];
    return lessonStudents.flatMap((student) => {
      const record = findLessonStudentRecord(records, lesson, student) ?? createEmptyRecord(lesson, student);
      const previousHomework = getLessonHomework(homeworks, lesson, student, "previous", lessons);
      const nextHomework = getLessonHomework(homeworks, lesson, student, "next");
      const supplementSchedules = getStudentSupplementSchedules(makeupTasks, student.studentId, { lesson, mode: "lesson_comment" });
      const testResultLines = getLessonTestResultLines(testSessions, testAttempts, lesson, student);
      return ["parent", "student"].flatMap((audience) => {
        if (audience === "parent" && record.notificationMutedParent) return [];
        if (audience === "student" && record.notificationMutedStudent) return [];
        const payloadSnapshot = buildLessonReservationPayloadSnapshot({
          audience,
          lesson,
          mode: notificationPlanMode,
          nextHomework,
          notificationTemplates: aiSettings.notificationTemplates,
          previousHomework,
          record,
          scheduledDate,
          student,
          supplementSchedules,
          testResultLines
        });
        return [{
          fingerprint: getLessonReservationPayloadFingerprint(payloadSnapshot),
          notificationJobId: createLessonNotificationJobId(lesson.lessonId, student.studentId, audience)
        }];
      });
    });
  }

  function getSolapiReservationSyncStatus() {
    if (reservationApplyState === "applying") {
      return { detail: "Solapi 실제 예약/취소를 반영하는 중입니다.", state: "applying", label: "Solapi 반영 중" };
    }
    if (reservationApplyState === "failed") {
      return { detail: "예약 확인에서 실패 항목을 확인한 뒤 다시 반영하세요.", state: "failed", label: "Solapi 반영 실패" };
    }
    if (hasJournalDraftChanges) {
      return { detail: "먼저 수업일지 변경 저장을 눌러 최신 저장본을 확정하세요.", state: "blocked", label: "수업일지 저장 필요" };
    }
    if (notificationPlanMode === "none") {
      return activeLessonReservationJobs.length
        ? { detail: `활성 예약 ${activeLessonReservationJobs.length}건을 취소 반영해야 합니다.`, state: "needs", label: "Solapi 취소 반영 필요" }
        : { detail: "현재 활성 Solapi 예약이 없습니다.", state: "synced", label: "Solapi 예약 없음" };
    }
    if (notificationPlanMode === "manual" && !lessonNotificationPlan?.scheduledAt) {
      return { detail: "수동 예약 시각이 없습니다.", state: "failed", label: "예약 시각 없음" };
    }
    if (notificationPlanMode !== "manual") {
      const delayMinutes = notificationPlanMode === "delay30" ? 30 : 0;
      if (isLessonAlimtalkScheduleExpired(lesson, delayMinutes)) {
        if (hasSolapiResultRefreshTarget) {
          return {
            detail: "예약 시각이 지났습니다. 새 예약이 아니라 Solapi 발송결과를 OS 상태에 반영하세요.",
            state: "resultDue",
            label: "발송결과 확인 필요"
          };
        }
        if (failedSolapiResultJobs.length) {
          return {
            detail: `Solapi 발송 실패 ${failedSolapiResultJobs.length}건이 반영되었습니다. 예약 확인에서 실패 내용을 확인하세요.`,
            state: "failed",
            label: `발송 실패 ${failedSolapiResultJobs.length}건`
          };
        }
        if (completedSolapiResultJobs.length) {
          return {
            detail: `Solapi 발송 완료 ${completedSolapiResultJobs.length}건이 OS 상태에 반영되었습니다.`,
            state: "synced",
            label: "발송 결과 반영 완료"
          };
        }
        return { detail: "기본 예약 시각이 지나 수동 예약으로 다시 잡아야 합니다.", state: "failed", label: "예약 시간 지남" };
      }
    }
    const expectedItems = getExpectedSolapiReservationItems();
    if (!expectedItems.length) {
      return activeLessonReservationJobs.length
        ? { detail: `발송 대상은 없지만 활성 예약 ${activeLessonReservationJobs.length}건이 남아 있습니다.`, state: "needs", label: "Solapi 취소 반영 필요" }
        : { detail: "현재 발송 대상이 없습니다.", state: "synced", label: "Solapi 예약 대상 없음" };
    }
    const expectedIds = new Set(expectedItems.map((item) => item.notificationJobId));
    const activeById = new Map(activeLessonReservationJobs.map((job) => [job.notificationJobId, job]));
    const missingCount = expectedItems.filter((item) => !activeById.has(item.notificationJobId)).length;
    const extraCount = activeLessonReservationJobs.filter((job) => !expectedIds.has(job.notificationJobId)).length;
    const staleCount = expectedItems.filter((item) => {
      const job = activeById.get(item.notificationJobId);
      if (!job) return false;
      if (job.status !== "scheduled") return true;
      if (job.provider !== "solapi" || !getNotificationJobProviderReference(job)) return true;
      const payloadFingerprint = getLessonReservationPayloadFingerprint({
        ...(job.payload ?? {}),
        recipient: job.recipient,
        scheduledDate: job.scheduledAt || job.payload?.scheduledDate || ""
      });
      return payloadFingerprint !== item.fingerprint;
    }).length;
    if (missingCount || extraCount || staleCount) {
      return {
        detail: [`누락 ${missingCount}건`, `남은 예약 ${extraCount}건`, `내용 변경 ${staleCount}건`].join(" · "),
        state: "needs",
        label: "Solapi 예약 업데이트 필요"
      };
    }
    return { detail: `저장된 최종본 기준 Solapi 예약 ${expectedItems.length}건이 맞습니다.`, state: "synced", label: "Solapi 반영 완료" };
  }

  const solapiReservationSyncStatus = getSolapiReservationSyncStatus();
  const notificationPlanSummaryText = notificationPlanMode === "none"
    ? "알림톡 없음"
    : notificationPlanMode === "delay30"
      ? `${isDelayedScheduleExpired ? "30분 지연 시간 지남" : "30분 지연"} · ${delayedAlimtalkTimeLabel}`
      : notificationPlanMode === "manual"
        ? `수동 예약 · ${lessonNotificationPlan?.scheduledAt ? formatKoreaTimeLabel(lessonNotificationPlan.scheduledAt) : "시각 미정"}`
        : defaultScheduleHintText;
  const solapiApplyButtonLabel =
    reservationApplyState === "applying"
      ? "Solapi 반영 중"
      : notificationPlanMode === "none"
        ? "Solapi 취소 반영"
        : solapiReservationSyncStatus.state === "needs"
          ? "Solapi 예약 업데이트"
          : "Solapi 예약 반영";
  const canApplySolapiReservation =
    Boolean(onApplyLessonNotificationPlan) &&
    !hasJournalDraftChanges &&
    reservationApplyState !== "applying" &&
    solapiReservationSyncStatus.state !== "resultDue" &&
    (solapiReservationSyncStatus.state === "needs" || reservationApplyState === "failed");
  const canRefreshSolapiResults =
    Boolean(onReconcileSolapiNotificationResults) &&
    !hasJournalDraftChanges &&
    solapiResultRefreshState !== "loading" &&
    hasSolapiResultRefreshTarget;
  const solapiResultRefreshTitle = solapiResultRefreshTargetJobs.length
    ? `Solapi 발송 원천 ${solapiResultRefreshTargetJobs.length}건을 OS 상태에 반영합니다.`
    : "지난 예약의 Solapi 발송결과를 OS 상태에 반영합니다.";

  function startJournalEditMode() {
    setJournalEditMode(true);
    setJournalManualSaveMessage("수업일지 · 편집 중");
    const firstStudent = lessonStudents[0];
    if (!firstStudent) return;
    const firstRecordId = createLessonStudentRecordId(lesson.lessonId, firstStudent.studentId);
    setEditingMemoKey(`${firstRecordId}:lessonMaterial`);
  }

  async function refreshReservationAudit() {
    setReservationAudit((current) => ({ ...current, message: "예약 원천을 조회하는 중입니다.", state: "loading" }));
    const osPath = `/api/notification-jobs?date=${encodeURIComponent(lesson.date)}&lessonId=${encodeURIComponent(lesson.lessonId)}&limit=500&includeResult=true`;
    const solapiGroupsPath = `/api/solapi/groups?date=${encodeURIComponent(lesson.date)}&limit=100`;
    const solapiMessagesPath = `/api/solapi/messages?date=${encodeURIComponent(lesson.date)}&limit=100`;
    const [osResult, groupsResult, messagesResult] = await Promise.allSettled([
      getJsonWithTimeout(osPath, 12000, "OS 알림톡 예약 큐 조회가 12초를 넘었습니다."),
      getJsonWithTimeout(solapiGroupsPath, 12000, "Solapi 그룹 이력 조회가 12초를 넘었습니다."),
      getJsonWithTimeout(solapiMessagesPath, 12000, "Solapi 메시지 이력 조회가 12초를 넘었습니다.")
    ]);
    const osJobs = osResult.status === "fulfilled" ? osResult.value.notificationJobs ?? [] : null;
    const solapiGroups = groupsResult.status === "fulfilled" ? groupsResult.value.groups ?? [] : [];
    const solapiMessages = messagesResult.status === "fulfilled" ? messagesResult.value.messages ?? [] : [];
    const errors = [osResult, groupsResult, messagesResult]
      .filter((result) => result.status === "rejected")
      .map((result) => result.reason?.message ?? "조회 실패");
    setReservationAudit({
      message: errors.length
        ? `일부 조회 실패: ${errors.join(" / ")}`
        : `OS 예약 ${osJobs?.length ?? 0}건 · Solapi 그룹 ${solapiGroups.length}건 · Solapi 메시지 ${solapiMessages.length}건`,
      osJobs,
      solapiGroups,
      solapiMessages,
      state: errors.length ? "partial" : "ready"
    });
  }

  useEffect(() => {
    if (!reservationModalOpen) return;
    refreshReservationAudit().catch((error) => {
      setReservationAudit((current) => ({
        ...current,
        message: `예약 원천 조회 실패: ${error.message}`,
        state: "failed"
      }));
    });
  }, [lesson.date, lesson.lessonId, reservationModalOpen]);

  async function cancelReservationJob(job) {
    if (!job?.notificationJobId || cancelingReservationJobId) return;
    if (typeof window !== "undefined" && !window.confirm("이 알림톡 예약 1건을 취소할까요? 취소한 기록은 이력에 남습니다.")) return;
    setCancelingReservationJobId(job.notificationJobId);
    try {
      const result = await onCancelNotificationJob?.(job, "수업일지 예약 확인에서 취소");
      if (result?.notificationJob) {
        setReservationAudit((current) => ({
          ...current,
          message: "예약 1건을 취소했습니다.",
          osJobs: Array.isArray(current.osJobs)
            ? [
                result.notificationJob,
                ...current.osJobs.filter((item) => item.notificationJobId !== result.notificationJob.notificationJobId)
              ]
            : current.osJobs,
          state: current.state === "idle" ? "ready" : current.state
        }));
      } else {
        await refreshReservationAudit();
      }
    } catch (error) {
      setReservationAudit((current) => ({ ...current, message: `예약 취소 실패: ${error.message}`, state: "failed" }));
    } finally {
      setCancelingReservationJobId("");
    }
  }

  async function cancelSolapiGroup(group) {
    if (!group?.groupId || cancelingSolapiGroupId) return;
    const count = group.count?.total ? ` ${group.count.total}건` : "";
    if (typeof window !== "undefined" && !window.confirm(`Solapi 그룹 예약${count}을 취소할까요? groupId: ${group.groupId}`)) return;
    setCancelingSolapiGroupId(group.groupId);
    try {
      await postJson("/api/solapi/groups/cancel", { groupId: group.groupId });
      setReservationAudit((current) => ({
        ...current,
        message: "Solapi 그룹 예약을 취소했습니다.",
        solapiGroups: current.solapiGroups.map((item) =>
          item.groupId === group.groupId ? { ...item, status: "CANCELED", dateCompleted: item.dateCompleted || new Date().toISOString() } : item
        ),
        state: current.state === "idle" ? "ready" : current.state
      }));
    } catch (error) {
      setReservationAudit((current) => ({ ...current, message: `Solapi 그룹 취소 실패: ${error.message}`, state: "failed" }));
    } finally {
      setCancelingSolapiGroupId("");
    }
  }


  if (isSupplementMakeupLesson) {
    return (
      <SupplementMakeupLessonDetail
        attendanceSettings={attendanceSettings}
        homeworks={homeworks}
        lesson={lesson}
        lessons={lessons}
        onDeleteLesson={onDeleteLesson}
        onEditLesson={onEditLesson}
        onOpenAttendance={onOpenAttendance}
        onPassTask={onPassMakeupTask}
        onScheduleTask={onScheduleMakeupTask}
        onUpdateTask={onUpdateMakeupTask}
        records={records}
        students={students}
        task={linkedMakeupTask}
      />
    );
  }
  if (isExamPrepLessonCurrent) {
    return (
      <ExamPrepLessonDetail
        lesson={lesson}
        onDeleteLesson={onDeleteLesson}
        onEditLesson={onEditLesson}
      />
    );
  }
  function openCommentComposer(audience, targetStudent, baseRecord, previousHomework, nextHomework) {
    const field = audience === "student" ? "studentComment" : "teacherComment";
    const supplementSchedules = getStudentSupplementSchedules(makeupTasks, targetStudent.studentId, { lesson, mode: "lesson_comment" });
    const testResultLines = getLessonTestResultLines(testSessions, testAttempts, lesson, targetStudent);
    const draft = buildInitialCommentDraft({
      audience,
      existingComment: baseRecord?.[field] ?? "",
      record: baseRecord,
      supplementSchedules
    });
    setCommentModal({
      audience,
      initialCommentDraft: draft,
      nextHomework,
      previousHomework,
      record: baseRecord,
      student: targetStudent,
      supplementSchedules,
      testResultLines
    });
  }

  function getCommentModalRecord() {
    if (!commentModal) return null;
    const recordId = createLessonStudentRecordId(lesson.lessonId, commentModal.student.studentId);
    return records.find((item) => item.lessonStudentRecordId === recordId) ?? commentModal.record;
  }

  function getPreviousLessonMemoContext(student) {
    const sourceRecords = allRecords.length ? allRecords : records;
    const lessonById = new Map(lessons.map((item) => [item.lessonId, item]));
    const getRecordLessonDate = (record) => {
      const sourceLesson = lessonById.get(record.lessonId);
      if (sourceLesson?.date) return sourceLesson.date;
      return String(record.lessonStudentRecordId ?? "").match(/\d{4}-\d{2}-\d{2}/)?.[0] ?? "";
    };
    const getRecordLessonSortValue = (record) => {
      const sourceLesson = lessonById.get(record.lessonId);
      return `${getRecordLessonDate(record)} ${sourceLesson?.startTime ?? ""}`;
    };
    const recordMatchesCurrentLessonGroup = (record) => {
      const sourceLesson = lessonById.get(record.lessonId);
      if (!sourceLesson) return !isSpecialLectureLesson(lesson);
      return isSameLessonGroup(lesson, sourceLesson);
    };
    const acknowledgedMemoCutoff = sourceRecords
      .filter((item) =>
        item.studentId === student.studentId &&
        item.prepMemoCheckedAt &&
        item.prepMemoCheckedSourceDate &&
        getRecordLessonDate(item) <= lesson.date
      )
      .sort((recordA, recordB) => (
        String(recordB.prepMemoCheckedSourceDate).localeCompare(String(recordA.prepMemoCheckedSourceDate)) ||
        String(recordB.prepMemoCheckedAt).localeCompare(String(recordA.prepMemoCheckedAt))
      ))[0] ?? null;
    const acknowledgedMemoCutoffDate = acknowledgedMemoCutoff?.prepMemoCheckedSourceDate ?? "";
    const isMemoRecordAcknowledged = (record) => {
      const recordDate = getRecordLessonDate(record);
      return Boolean(acknowledgedMemoCutoffDate && recordDate && recordDate <= acknowledgedMemoCutoffDate);
    };
    const previousLessons = lessons
      .filter((item) =>
        item.lessonId !== lesson.lessonId &&
        item.date < lesson.date &&
        item.status !== "canceled" &&
        item.studentIds?.includes(student.studentId) &&
        isSameLessonGroup(lesson, item)
      )
      .sort((lessonA, lessonB) => (
        `${lessonB.date} ${lessonB.startTime ?? ""}`.localeCompare(`${lessonA.date} ${lessonA.startTime ?? ""}`)
      ));

    const previousLessonRecordInCurrentGroup = previousLessons
      .map((previousLesson) =>
        sourceRecords.find((item) => item.lessonId === previousLesson.lessonId && item.studentId === student.studentId)
      )
      .find(Boolean);
    const bridgedPreviousLesson = previousLessons.length === 0
      ? findPreviousLessonForStudent(lessons, lesson, student.studentId, { allowRegularClassFallback: true })
      : null;
    const bridgedPreviousLessonRecord = bridgedPreviousLesson
      ? sourceRecords.find((item) => item.lessonId === bridgedPreviousLesson.lessonId && item.studentId === student.studentId) ?? null
      : null;
    const previousLessonRecord = previousLessonRecordInCurrentGroup ?? bridgedPreviousLessonRecord;
    const visiblePreviousMemoRecord = previousLessonRecord?.preparationMemo?.trim() && !isMemoRecordAcknowledged(previousLessonRecord)
      ? previousLessonRecord
      : null;

    const referenceMemoRecord = sourceRecords
      .filter((item) =>
        item.lessonId !== lesson.lessonId &&
        item.studentId === student.studentId &&
        item.preparationMemo?.trim() &&
        getRecordLessonDate(item) < lesson.date
        && recordMatchesCurrentLessonGroup(item)
        && !isMemoRecordAcknowledged(item)
        && item.lessonId !== previousLessonRecord?.lessonId
      )
      .sort((recordA, recordB) => getRecordLessonSortValue(recordB).localeCompare(getRecordLessonSortValue(recordA)))[0];

    return {
      acknowledgedMemoCutoff,
      acknowledgedMemoCutoffDate,
      previousMemoRecord: visiblePreviousMemoRecord,
      previousRecord: previousLessonRecord ?? null,
      referenceRecord: visiblePreviousMemoRecord ? null : referenceMemoRecord ?? null
    };
  }

  function getStudentReservationStatus(student, target) {
    const notificationType = target === "student" ? "student_comment" : "parent_comment";
    return auditedLessonNotificationJobs
      .filter((job) => job.studentId === student.studentId && job.notificationType === notificationType)
      .sort(sortNotificationJobsForCurrentStatus)[0] ?? null;
  }

  function getEditableRecord(recordId, baseRecord) {
    return journalRecordDrafts[recordId] ?? baseRecord;
  }

  function updateJournalRecordDraft(student, baseRecord, field, value) {
    updateJournalRecordDraftPatch(student, baseRecord, {
      [field]: value,
      ...(field === "assignmentStatus" ? { incompleteHomework: value } : {}),
      ...(field === "teacherComment" ? { teacherCommentSendStatus: "" } : {}),
      ...(field === "studentComment" ? { studentCommentSendStatus: "" } : {})
    });
  }

  function handleAssignmentStatusChange(student, baseRecord, previousHomework, value) {
    const normalizedValue = normalizeAssignmentStatusValue(value);
    const homeworkTitle = previousHomework?.title || previousHomework?.sourceLabel || "";
    removeJournalMakeupTaskDraft(student);
    if (normalizedValue === "not_checked" && homeworkTitle) {
      updateJournalRecordDraftPatch(student, baseRecord, {
        assignmentStatus: normalizedValue,
        incompleteHomework: normalizedValue,
        needsMakeup: false,
        ...getHomeworkFollowupPatch(baseRecord, "next_lesson", previousHomework),
        prepParentVisible: true,
        prepStudentVisible: true,
        teacherCommentSendStatus: "",
        studentCommentSendStatus: ""
      });
      setJournalManualSaveMessage("수업일지 · 미검사는 다음 정규수업 확인 문구를 오늘 알림톡에 반영합니다.");
      return;
    }
    if (!getHomeworkFollowupOptionsForAssignmentStatus(normalizedValue).length) {
      updateJournalRecordDraftPatch(student, baseRecord, {
        assignmentStatus: normalizedValue,
        incompleteHomework: normalizedValue,
        ...getHomeworkFollowupPatch(baseRecord)
      });
      return;
    }
    updateJournalRecordDraft(student, baseRecord, "assignmentStatus", normalizedValue);
  }

  function updateJournalRecordDraftPatch(student, baseRecord, patch = {}) {
    if (!journalEditMode) return;
    const recordId = createLessonStudentRecordId(lesson.lessonId, student.studentId);
    const nowIso = new Date().toISOString();
    const nextRecord = {
      ...createEmptyRecord(lesson, student),
      ...(journalRecordDrafts[recordId] ?? baseRecord ?? {}),
      lessonStudentRecordId: recordId,
      lessonId: lesson.lessonId,
      studentId: student.studentId,
      ...patch,
      updatedBy: "instructor_owner_001",
      updatedAt: nowIso
    };
    setJournalRecordDrafts((current) => ({ ...current, [recordId]: nextRecord }));
    setJournalManualSaveMessage("수업일지 · 저장 필요");
  }

  function removeJournalMakeupTaskDraft(student) {
    const recordId = createLessonStudentRecordId(lesson.lessonId, student.studentId);
    setJournalMakeupTaskDrafts((current) => {
      if (!current[recordId]) return current;
      const next = { ...current };
      delete next[recordId];
      return next;
    });
  }

  function applyHomeworkFollowupMethod(student, baseRecord, previousHomework, method) {
    if (!journalEditMode || !previousHomework) return;
    const homeworkTitle = previousHomework.title || previousHomework.sourceLabel || "지난 숙제";
    const clearFollowupPatch = getHomeworkFollowupPatch(baseRecord);
    const commonPatch = {
      assignmentStatus: normalizeAssignmentStatusValue(baseRecord.assignmentStatus ?? baseRecord.incompleteHomework ?? ""),
      incompleteHomework: normalizeAssignmentStatusValue(baseRecord.assignmentStatus ?? baseRecord.incompleteHomework ?? ""),
      teacherCommentSendStatus: "",
      studentCommentSendStatus: ""
    };

    if (method === "arrival_makeup") {
      const recordId = createLessonStudentRecordId(lesson.lessonId, student.studentId);
      const makeupTask = {
        taskType: "homework_makeup",
        studentId: student.studentId,
        sourceId: previousHomework.homeworkId,
        sourceHomeworkId: previousHomework.homeworkId,
        sourceLessonId: previousHomework.lessonId || lesson.lessonId,
        sourceDate: previousHomework.assignedDate || lesson.date,
        sourceDueDate: previousHomework.dueDate || lesson.date,
        sourceLabel: homeworkTitle,
        reason: "등원보충 필요 숙제",
        supplementHomeworkNote: homeworkTitle,
        supplementMethod: "arrival_makeup"
      };
      setJournalMakeupTaskDrafts((current) => ({ ...current, [recordId]: makeupTask }));
      updateJournalRecordDraftPatch(student, baseRecord, {
        ...commonPatch,
        needsMakeup: true,
        ...clearFollowupPatch,
        prepParentVisible: Boolean(clearFollowupPatch.preparationMemo && baseRecord.prepParentVisible),
        prepStudentVisible: Boolean(clearFollowupPatch.preparationMemo && baseRecord.prepStudentVisible)
      });
      setJournalManualSaveMessage("수업일지 · 등원보충 초안 · 변경 저장 후 Supabase 반영");
      return;
    }

    removeJournalMakeupTaskDraft(student);
    updateJournalRecordDraftPatch(student, baseRecord, {
      ...commonPatch,
      needsMakeup: false,
      ...getHomeworkFollowupPatch(baseRecord, method, previousHomework),
      prepParentVisible: true,
      prepStudentVisible: true
    });
    setJournalManualSaveMessage(
      method === "next_lesson"
        ? "수업일지 · 다음 정규수업 확인 문구를 오늘 알림톡에 반영합니다."
        : "수업일지 · 수업 후 보충 문구를 오늘 알림톡에 반영합니다."
    );
  }

  function getHomeworkDraftKey(student, homeworkType) {
    return `${createLessonStudentRecordId(lesson.lessonId, student.studentId)}:${homeworkType}`;
  }

  function getHomeworkDraftTitle(student, homeworkType, homework) {
    return journalHomeworkDrafts[getHomeworkDraftKey(student, homeworkType)]?.title ?? homework?.title ?? "";
  }

  function updateJournalHomeworkDraft(student, homeworkType, title) {
    if (!journalEditMode) return;
    const key = getHomeworkDraftKey(student, homeworkType);
    setJournalHomeworkDrafts((current) => ({
      ...current,
      [key]: { homeworkType, key, studentId: student.studentId, title }
    }));
    setJournalManualSaveMessage("수업일지 · 저장 필요");
  }

  async function saveJournalDrafts() {
    if (!hasJournalDraftChanges) {
      setJournalEditMode(false);
      setJournalManualSaveMessage("수업일지 · 변경 없음");
      return;
    }
    setJournalManualSaveMessage("수업일지 · 저장 중");
    const saved = await onSaveLessonJournalDrafts?.(
      lesson,
      Object.values(journalRecordDrafts),
      Object.values(journalHomeworkDrafts),
      Object.values(journalMakeupTaskDrafts)
    );
    if (!saved?.ok) {
      setJournalManualSaveMessage(saved?.message || "수업일지 · 저장 실패 · 수정본 유지");
      return;
    }
    setJournalRecordDrafts({});
    setJournalHomeworkDrafts({});
    setJournalMakeupTaskDrafts({});
    setJournalEditMode(false);
    setJournalManualSaveMessage(saved.message || "수업일지 · 저장 완료");
    setReservationApplyState("idle");
  }

  async function applySolapiReservationPlan() {
    if (!onApplyLessonNotificationPlan || hasJournalDraftChanges) return;
    setReservationApplyState("applying");
    const result = await onApplyLessonNotificationPlan(lesson.lessonId);
    if (result?.ok === false) {
      setReservationApplyState("failed");
      setJournalManualSaveMessage(`Solapi 반영 실패 · ${result.error || "예약 확인 필요"}`);
      return;
    }
    setReservationApplyState("saved");
    setJournalManualSaveMessage(notificationPlanMode === "none" ? "Solapi 취소 반영 완료" : "Solapi 예약 반영 완료");
  }

  async function refreshSolapiSendResults() {
    if (!canRefreshSolapiResults) return;
    setSolapiResultRefreshState("loading");
    setJournalManualSaveMessage("솔라피 발송결과 · 확인 중");
    try {
      const result = await onReconcileSolapiNotificationResults?.({ date: lesson.date, lessonId: lesson.lessonId });
      setSolapiResultRefreshState("saved");
      setJournalManualSaveMessage(`솔라피 발송결과 · ${result?.updatedCount ?? 0}건 반영`);
      if (reservationModalOpen) {
        await refreshReservationAudit();
      }
    } catch (error) {
      setSolapiResultRefreshState("failed");
      setJournalManualSaveMessage(`솔라피 발송결과 실패 · ${error.message}`);
    }
  }

  function toggleReservationInspectMode(mode) {
    setReservationInspectMode((current) => current === mode ? "all" : mode);
  }

  function hasReservationIssue(job) {
    return job?.status === "canceled" || job?.status === "failed";
  }

  function getVisibleReservationStudents() {
    if (reservationInspectMode === "all") return lessonStudents;
    if (reservationInspectMode === "solapiScheduled") return [];
    return lessonStudents.filter((student) => {
      const parentJob = getStudentReservationStatus(student, "parent");
      const studentJob = getStudentReservationStatus(student, "student");
      if (reservationInspectMode === "parentScheduled") return parentJob?.status === "scheduled";
      if (reservationInspectMode === "studentScheduled") return studentJob?.status === "scheduled";
      if (reservationInspectMode === "issues") return hasReservationIssue(parentJob) || hasReservationIssue(studentJob);
      return true;
    });
  }

  function renderReservationSummaryButton(mode, label, count) {
    const active = reservationInspectMode === mode;
    return (
      <button
        aria-pressed={active}
        className={active ? "reservationSummaryCard active" : "reservationSummaryCard"}
        onClick={() => toggleReservationInspectMode(mode)}
        type="button"
      >
        <span>{label}</span>
        <strong>{count}건</strong>
      </button>
    );
  }

  function renderReservationStatusCell(job, isMuted = false) {
    if (isMuted) return <span className="reservationStatusCell muted">알림 제외</span>;
    const providerReference = getNotificationJobProviderReference(job);
    return (
      <span className="reservationStatusCell">
        <span>{formatNotificationJobStatus(job)}</span>
        {providerReference ? <small>Solapi {providerReference}</small> : null}
        {canCancelNotificationJob(job) ? (
          <button
            className="dangerSoftButton compact"
            disabled={cancelingReservationJobId === job.notificationJobId}
            onClick={() => cancelReservationJob(job)}
            type="button"
          >
            {cancelingReservationJobId === job.notificationJobId ? "취소 중" : "취소"}
          </button>
        ) : null}
      </span>
    );
  }

  function getEffectiveCommentSendStatus(record, student, target) {
    const jobStatus = formatNotificationJobStatus(getStudentReservationStatus(student, target));
    if (jobStatus && jobStatus !== "없음") return jobStatus;
    const persistedStatus = target === "student" ? record.studentCommentSendStatus : record.teacherCommentSendStatus;
    return getDisplayCommentSendStatus(persistedStatus);
  }

  return (
    <section className="lessonJournalPage">
      <header className="pageTop lessonJournalHeader">
        <button className="iconButton" onClick={onBack} type="button">‹</button>
        <div>
          <button className="linkTitleButton" onClick={onOpenExamPrep} type="button">{lesson.className}</button>
          <p className="muted">{lesson.date} · {formatLessonTimeRange(lesson)} · {lessonStudents.length}명</p>
        </div>
        <span className="shortcutHint">{lesson.lessonTopic || "수업일지"}</span>
        <button className="softButton" onClick={() => onEditLesson(lesson)} type="button">수업 수정</button>
        <button className="dangerButton" onClick={() => onDeleteLesson(lesson.lessonId)} type="button">수업 취소 처리</button>
      </header>

      {lessonAcademyReminders.length > 0 ? (
        <section className="panel lessonReminderPanel">
          <div className="sectionHeader slim">
            <div>
              <strong>수업 관련 운영 알림</strong>
              <p className="muted">대시보드 원본 알림 중 오늘 수업 학생과 연결된 항목입니다.</p>
            </div>
            <span className="countBadge">{lessonAcademyReminders.length}건</span>
          </div>
          <AcademyReminderList reminders={lessonAcademyReminders} students={students} templates={templates} />
        </section>
      ) : null}

      <section className="panel lessonSaveSummary" aria-label="발송 상태와 작업">
        <div className="lessonNotificationStatusRow">
          <strong>발송 상태</strong>
          <span className={`lessonNotificationPlanStatus ${notificationPlanMode}`} title={notificationPlanSummaryText}>
            {notificationPlanSummaryText}
          </span>
          {checkoutMissingStudents.length > 0 ? (
            <span className="checkoutMissingSummary" title={checkoutMissingStudents.map((student) => student.name).join(", ")}>
              하원 미체크 {checkoutMissingStudents.length}명
            </span>
          ) : null}
          <span
            aria-live="polite"
            className={`solapiReservationSync ${solapiReservationSyncStatus.state}`}
            title={solapiReservationSyncStatus.detail}
          >
            {solapiReservationSyncStatus.label}
          </span>
        </div>
        <div className="lessonNotificationActionRow">
          {!journalEditMode ? (
            <button className="schedulePlanButton" onClick={startJournalEditMode} type="button">
              수정 시작
            </button>
          ) : null}
          <label className="lessonNotificationPlanSelect">
            <span>예약 설정</span>
            <select
              aria-label="알림톡 예약 설정"
              onChange={(event) => onUpdateLessonNotificationPlan?.(lesson.lessonId, event.target.value)}
              value={notificationPlanMode}
            >
              {notificationPlanMode === "manual" ? (
                <option value="manual">수동 예약 · {lessonNotificationPlan?.scheduledAt ? formatKoreaTimeLabel(lessonNotificationPlan.scheduledAt) : "시각 미정"}</option>
              ) : null}
              <option disabled={isDefaultScheduleExpired} value="default">기본 예약 · {defaultAlimtalkTimeLabel}</option>
              <option disabled={isDelayedScheduleExpired} value="delay30">30분 지연 · {delayedAlimtalkTimeLabel}</option>
              <option value="none">알림톡 없음</option>
            </select>
          </label>
          <button
            className="schedulePlanButton check"
            onClick={() => {
              setReservationInspectMode("all");
              setReservationModalOpen(true);
            }}
            type="button"
          >
            예약 확인
          </button>
          {hasSolapiResultRefreshTarget ? (
            <button
              className={solapiResultRefreshState === "failed" ? "dangerSoftButton" : "schedulePlanButton check"}
              disabled={!canRefreshSolapiResults}
              onClick={refreshSolapiSendResults}
              title={solapiResultRefreshTitle}
              type="button"
            >
              {solapiResultRefreshState === "loading" ? "확인 중" : "발송 결과"}
            </button>
          ) : null}
          {canApplySolapiReservation || reservationApplyState === "applying" ? (
            <button
              className="sendButton"
              disabled={!canApplySolapiReservation}
              onClick={applySolapiReservationPlan}
              type="button"
            >
              {solapiApplyButtonLabel}
            </button>
          ) : null}
        </div>
      </section>

      {reservationModalOpen ? (
        <Modal
          className="reservationStatusModal"
          title="알림톡 예약 확인"
          subtitle={`${lesson.date} · ${lesson.className}`}
          onClose={() => setReservationModalOpen(false)}
        >
          <div className="reservationSummaryGrid">
            {renderReservationSummaryButton("parentScheduled", "OS 학부모 예약", scheduledParentCount)}
            {renderReservationSummaryButton("studentScheduled", "OS 학생 예약", scheduledStudentCount)}
            {renderReservationSummaryButton("solapiScheduled", "Solapi 예약 그룹", solapiScheduledGroups.length)}
            {renderReservationSummaryButton("issues", "취소/실패", canceledJobCount + failedJobCount)}
          </div>
          <div className="reservationModalActions">
            <span>{reservationAudit.message || "예약 기준: Solapi 실제 예약 + OS 검수 기록"}</span>
            <button
              className="softButton compact"
              disabled={reservationAudit.state === "loading"}
              onClick={refreshReservationAudit}
              type="button"
            >
              {reservationAudit.state === "loading" ? "조회 중" : "Solapi/OS 새로고침"}
            </button>
            {hasSolapiResultRefreshTarget ? (
              <button
                className="softButton compact"
                disabled={!canRefreshSolapiResults}
                onClick={refreshSolapiSendResults}
                type="button"
              >
                {solapiResultRefreshState === "loading" ? "확인 중" : "솔라피 발송결과"}
              </button>
            ) : null}
            {reservationInspectMode !== "all" ? (
              <button className="softButton compact" onClick={() => setReservationInspectMode("all")} type="button">
                전체 보기
              </button>
            ) : null}
            {canScheduleTodayTwoPm ? (
              <button
                className="sendButton"
                onClick={() => onScheduleLessonNotificationsAt?.(lesson.lessonId, todayTwoPmIso)}
                type="button"
              >
                오늘 14:00 일괄예약
              </button>
            ) : null}
          </div>
          {orphanScheduledJobs.length ? (
            <div className="reservationWarningBox">
              <strong>명단 밖 예약 {orphanScheduledJobs.length}건</strong>
              <span>현재 수업일지 명단에 없는 학생 예약입니다. 확인 후 취소하세요.</span>
              {orphanScheduledJobs.map((job) => (
                <button
                  className="dangerSoftButton compact"
                  disabled={cancelingReservationJobId === job.notificationJobId}
                  key={job.notificationJobId}
                  onClick={() => cancelReservationJob(job)}
                  type="button"
                >
                  {job.payload?.studentName || job.studentId} · {getNotificationJobLabel(job.notificationType)} 취소
                </button>
              ))}
            </div>
          ) : null}
          <div className="reservationInspectHeader">
            <strong>{reservationInspectLabels[reservationInspectMode] ?? "전체 예약"}</strong>
            <span>
              OS 예약 {auditedLessonNotificationJobs.length}건 · Solapi 그룹 {reservationAudit.solapiGroups.length}건 · Solapi 메시지 {solapiLessonMessages.length}건
            </span>
          </div>
          {shouldShowStudentReservationTable ? (
            <div className="reservationStatusTable">
              <div className="reservationStatusRow head">
                <span>학생</span>
                <span>학부모</span>
                <span>학생</span>
              </div>
              {getVisibleReservationStudents().length ? getVisibleReservationStudents().map((student) => {
                const record = findLessonStudentRecord(records, lesson, student) ?? createEmptyRecord(lesson, student);
                const parentJob = getStudentReservationStatus(student, "parent");
                const studentJob = getStudentReservationStatus(student, "student");
                return (
                  <div className="reservationStatusRow" key={student.studentId}>
                    <strong>{student.name}</strong>
                    {renderReservationStatusCell(parentJob, record.notificationMutedParent)}
                    {renderReservationStatusCell(studentJob, record.notificationMutedStudent)}
                  </div>
                );
              }) : (
                <EmptyState as="p" className="emptyState compact">해당 조건의 학생 예약이 없습니다.</EmptyState>
              )}
            </div>
          ) : null}
          {shouldShowIssueAudit ? (
            <section className="reservationIssueList">
              <div className="reservationAuditHeader">
                <strong>OS 취소/실패</strong>
                <span>{issueReservationJobs.length}건</span>
              </div>
              <div className="reservationAuditList">
                {issueReservationJobs.length ? issueReservationJobs.map((job) => (
                  <article key={job.notificationJobId}>
                    <strong>{job.payload?.studentName || students.find((student) => student.studentId === job.studentId)?.name || job.studentId || "학생"}</strong>
                    <span>{getNotificationJobLabel(job.notificationType)} · {formatNotificationJobStatus(job)}</span>
                    <small>{job.notificationJobId}</small>
                  </article>
                )) : (
                  <EmptyState as="p" className="emptyState compact">취소/실패한 OS 예약이 없습니다.</EmptyState>
                )}
              </div>
            </section>
          ) : null}
          {shouldShowSolapiAudit ? (
          <div className="reservationAuditGrid">
            <section>
              <div className="reservationAuditHeader">
                <strong>Solapi 그룹</strong>
                <span>{displayedSolapiGroups.length}건</span>
              </div>
              <div className="reservationAuditList">
                {displayedSolapiGroups.length ? displayedSolapiGroups.map((group) => (
                  <article key={group.groupId}>
                    <strong>{group.scheduledDate ? formatKoreaTimeLabel(group.scheduledDate) : formatKoreaTimeLabel(group.dateCreated)}</strong>
                    <span>{group.status || "-"} · {group.count?.total ?? 0}건</span>
                    <small>{group.groupId}</small>
                    {group.scheduledDate && !group.dateSent && !group.dateCompleted ? (
                      <button
                        className="dangerSoftButton compact"
                        disabled={cancelingSolapiGroupId === group.groupId}
                        onClick={() => cancelSolapiGroup(group)}
                        type="button"
                      >
                        {cancelingSolapiGroupId === group.groupId ? "취소 중" : "그룹 취소"}
                      </button>
                    ) : null}
                  </article>
                )) : (
                  <EmptyState as="p" className="emptyState compact">Solapi 그룹 이력이 없습니다.</EmptyState>
                )}
              </div>
            </section>
            <section>
              <div className="reservationAuditHeader">
                <strong>Solapi 메시지</strong>
                <span>{displayedSolapiMessages.length}건</span>
              </div>
              <div className="reservationAuditList">
                {displayedSolapiMessages.length ? displayedSolapiMessages.map((message) => (
                  <article key={message.messageId || `${message.groupId}_${message.to}`}>
                    <strong>{message.customFields?.studentName || maskPhoneForDisplay(message.to)}</strong>
                    <span>{message.statusCode || message.status || "-"} · {formatKoreaTimeLabel(message.dateCreated)}</span>
                    <small>{message.messageId || message.groupId}</small>
                  </article>
                )) : (
                  <EmptyState as="p" className="emptyState compact">이 수업 학생과 매칭되는 Solapi 메시지가 없습니다.</EmptyState>
                )}
              </div>
            </section>
          </div>
          ) : null}
        </Modal>
      ) : null}

      <section className="panel journalTablePanel">
        <div className={journalEditMode ? "journalTable editing" : "journalTable"}>
          <div className="journalRow journalHead">
            <span>학생</span>
            <span>수업메모</span>
            <span>출결</span>
            <span>강의 교재</span>
            <span>강의 내용</span>
            <span>지난 숙제</span>
            <span>다음 숙제</span>
            <span>과제 상태</span>
            <span>학부모 알림톡</span>
            <span>학생 알림톡</span>
          </div>
          {lessonStudents.map((student) => {
            const recordId = createLessonStudentRecordId(lesson.lessonId, student.studentId);
            const persistedRecord = findLessonStudentRecord(records, lesson, student) ?? createEmptyRecord(lesson, student);
            const record = getEditableRecord(recordId, persistedRecord);
            const attendanceLesson = applyStudentScheduleToLesson(lesson, student);
            const previousHomework = getLessonHomework(homeworks, lesson, student, "previous", lessons);
            const nextHomework = getLessonHomework(homeworks, lesson, student, "next");
            const previousHomeworkTitle = getHomeworkDraftTitle(student, "previous", previousHomework);
            const nextHomeworkTitle = getHomeworkDraftTitle(student, "next", nextHomework);
            const effectivePreviousHomework = previousHomeworkTitle !== (previousHomework?.title ?? "")
              ? { ...(previousHomework ?? {}), title: previousHomeworkTitle }
              : previousHomework;
            const effectiveNextHomework = nextHomeworkTitle !== (nextHomework?.title ?? "")
              ? { ...(nextHomework ?? {}), title: nextHomeworkTitle }
              : nextHomework;
            const attendanceDisplay = getAttendanceDisplay(record, attendanceLesson, attendanceSettings.lateGraceMinutes);
            const checkoutMissing = hasMissingCheckOut(record, attendanceLesson);
            const previousMemoContext = getPreviousLessonMemoContext(student);
            const previousRecord = previousMemoContext.previousRecord;
            const previousMemoRecord = previousMemoContext.previousMemoRecord;
            const referenceRecord = previousMemoContext.referenceRecord;
            const previousLessonMaterial = previousRecord?.lessonMaterial?.trim() ?? "";
            const previousLessonContent = getLessonContent(previousRecord);
            const previousPreparationMemo = previousMemoRecord?.preparationMemo?.trim() ?? "";
            const referencePreparationMemo = referenceRecord?.preparationMemo?.trim() ?? "";
            const previousHomeworkFollowup = getHomeworkFollowupFromRecord(previousRecord ?? {})
              ?? getHomeworkFollowupFromRecord(referenceRecord ?? {});
            const pendingHomeworkFollowup = previousHomeworkFollowup?.method === "next_lesson"
              ? previousHomeworkFollowup
              : null;
            const hasCheckedPriorPrepMemo = Boolean(previousMemoContext.acknowledgedMemoCutoffDate);
            const hasCurrentMemo = Boolean(record.preparationMemo?.trim());
            const priorMemoNeedsAttention = Boolean(previousPreparationMemo || referencePreparationMemo);
            const priorMemoAttentionLabel = previousPreparationMemo ? "직전 메모 확인" : "참고 메모 확인";
            const memoButtonDescription = [
              hasCurrentMemo ? "현재 메모 작성됨" : "현재 메모 미작성",
              priorMemoNeedsAttention
                ? priorMemoAttentionLabel
                : hasCheckedPriorPrepMemo
                  ? "이전 메모 확인 완료"
                  : "이전 메모 없음",
              record.prepStudentVisible && record.prepParentVisible
                ? "학생·학부모 작성창으로 가져오기"
                : record.prepStudentVisible
                  ? "학생 작성창으로 가져오기"
                  : record.prepParentVisible
                    ? "학부모 작성창으로 가져오기"
                    : "작성창 가져오기 안 함"
            ].join(" · ");
            const parentCommentSendStatus = getEffectiveCommentSendStatus(record, student, "parent");
            const studentCommentSendStatus = getEffectiveCommentSendStatus(record, student, "student");
            const parentCommentState = getCommentButtonState(record.teacherComment, parentCommentSendStatus);
            const studentCommentState = getCommentButtonState(record.studentComment, studentCommentSendStatus);
            const isParentNotificationOff = isLessonNotificationOff || record.notificationMutedParent;
            const isStudentNotificationOff = isLessonNotificationOff || record.notificationMutedStudent;
            const assignmentStatusValue = normalizeAssignmentStatusValue(record.assignmentStatus ?? record.incompleteHomework ?? "");
            const homeworkFollowupOptions = getHomeworkFollowupOptionsForAssignmentStatus(assignmentStatusValue);
            const shouldShowHomeworkFollowupActions =
              journalEditMode &&
              Boolean(effectivePreviousHomework?.title) &&
              homeworkFollowupOptions.length > 0;
            const selectedHomeworkFollowupMethod = getHomeworkFollowupMethodFromRecord(record);

            return (
              <div className="journalRow" key={student.studentId}>
                <span className="studentCell compact">
                  <span className="journalStudentTopLine">
                    <strong>{student.name}</strong>
                    <button
                      aria-label={`${student.name} 학생 화면 보기`}
                      className="studentPortalPreviewButton"
                      onClick={() => setStudentPreviewId(student.studentId)}
                      type="button"
                    >
                      👤
                    </button>
                  </span>
                  <small>{student.grade || "고1"} · {student.schoolName || "학교 미입력"}</small>
                  {attendanceLesson.studentScheduleType === "official" ||
                  attendanceLesson.studentScheduleType === "adjusted" ||
                  attendanceLesson.studentScheduleType === "profile" ? (
                    <small className={[
                      "specialLectureStudentTime",
                      attendanceLesson.studentScheduleType === "adjusted" ? "adjusted" : "",
                      attendanceLesson.studentScheduleType === "profile" ? "profile" : ""
                    ].filter(Boolean).join(" ")}>
                      {attendanceLesson.startTime}-{attendanceLesson.endTime}
                    </small>
                  ) : null}
                </span>
                <div className="journalPrepCell">
                  <button
                    aria-label={`${student.name} 수업메모 · ${memoButtonDescription}`}
                    className="prepMemoButton"
                    onClick={() => setPrepMemoModal({
                      acknowledgedMemoCutoff: previousMemoContext.acknowledgedMemoCutoff,
                      nextHomework,
                      previousHomework,
                      previousMemoRecord,
                      previousRecord,
                      record,
                      referenceRecord,
                      student
                    })}
                    type="button"
                  >
                    <span>수업메모</span>
                    {hasCurrentMemo ? <span aria-hidden="true" className="prepMemoWrittenMark">✓</span> : null}
                    {priorMemoNeedsAttention ? <span aria-hidden="true" className="prepMemoAttentionMark">!</span> : null}
                  </button>
                </div>
                <button
                  className={`attendanceBadge attendance-${attendanceDisplay.statusClass ?? record.attendanceStatus ?? "pending"}`}
                  onClick={() => onOpenAttendance({ lesson: attendanceLesson, record, student })}
                  type="button"
                >
                  <span>{attendanceDisplay.label}</span>
                  {attendanceDisplay.detail ? <small>{attendanceDisplay.detail}</small> : null}
                  {attendanceDisplay.dateMismatch ? <small className="attendanceMismatchText">확인 필요</small> : null}
                  {checkoutMissing ? <small className="checkoutMissingText">하원 미체크</small> : null}
                </button>
                <EditableMemoCard
                  disabled={!journalEditMode}
                  editKey={`${recordId}:lessonMaterial`}
                  editingKey={editingMemoKey}
                  onChange={(value) => updateJournalRecordDraft(student, record, "lessonMaterial", value)}
                  onEdit={setEditingMemoKey}
                  placeholder={previousLessonMaterial || student.textbook || student.currentTextbook || "강의 교재"}
                  value={record.lessonMaterial ?? ""}
                />
                <EditableMemoCard
                  disabled={!journalEditMode}
                  editKey={`${recordId}:lessonProgress`}
                  editingKey={editingMemoKey}
                  onChange={(value) => updateJournalRecordDraft(student, record, "lessonProgress", value)}
                  onEdit={setEditingMemoKey}
                  placeholder={previousLessonContent || "오늘 강의 내용"}
                  value={record.lessonProgress ?? record.progress ?? ""}
                />
                <EditableMemoCard
                  disabled={!journalEditMode}
                  editKey={`${recordId}:previousHomework`}
                  editingKey={editingMemoKey}
                  onChange={(value) => updateJournalHomeworkDraft(student, "previous", value)}
                  onEdit={setEditingMemoKey}
                  placeholder="지난 숙제"
                  value={previousHomeworkTitle}
                />
                <EditableMemoCard
                  disabled={!journalEditMode}
                  editKey={`${recordId}:nextHomework`}
                  editingKey={editingMemoKey}
                  onChange={(value) => updateJournalHomeworkDraft(student, "next", value)}
                  onEdit={setEditingMemoKey}
                  placeholder="다음 숙제"
                  value={nextHomeworkTitle}
                />
                <div className="assignmentStatusCell">
                  <select
                    className="assignmentStatusSelect"
                    disabled={!journalEditMode}
                    value={assignmentStatusValue}
                    onChange={(event) => handleAssignmentStatusChange(student, record, effectivePreviousHomework, event.target.value)}
                  >
                    {assignmentStatusOptions.map((option) => (
                      <option key={option.value || "empty"} value={option.value}>{option.label}</option>
                    ))}
                  </select>
                  {shouldShowHomeworkFollowupActions ? (
                    <div className="homeworkFollowupActions" aria-label="숙제보충 처리 방식">
                      {homeworkFollowupOptions.map((method) => (
                        <button
                          className={selectedHomeworkFollowupMethod === method.id ? "active" : ""}
                          key={method.id}
                          onClick={() => applyHomeworkFollowupMethod(student, record, effectivePreviousHomework, method.id)}
                          type="button"
                        >
                          {method.label}
                        </button>
                      ))}
                    </div>
                  ) : null}
                  {pendingHomeworkFollowup ? (
                    <span className="homeworkFollowupCheck">
                      확인할 숙제 · {pendingHomeworkFollowup.text}
                    </span>
                  ) : null}
                </div>
                <div className="journalCommentCell">
                  <button
                    className={`commentOpenButton comment-${parentCommentState}${isParentNotificationOff ? " notification-off" : ""}`}
                    onClick={() => openCommentComposer("parent", student, record, effectivePreviousHomework, effectiveNextHomework)}
                    type="button"
                  >
                    학부모 알림톡
                  </button>
                  <small className={`commentStatusText comment-${parentCommentState}`}>
                    {getCommentStatusLabel(record.teacherComment, parentCommentSendStatus)}
                  </small>
                  <button
                    className={[
                      "notificationMuteButton",
                      record.notificationMutedParent ? "active" : "",
                      isLessonNotificationOff && !record.notificationMutedParent ? "planOff" : ""
                    ].filter(Boolean).join(" ")}
                    onClick={() => onToggleStudentNotificationMute?.(lesson, student, "parent")}
                    title={isLessonNotificationOff ? "현재 수업 발송 계획이 알림톡 없음입니다." : ""}
                    type="button"
                  >
                    {record.notificationMutedParent ? "제외 해제" : "알림 제외"}
                  </button>
                </div>
                <div className="journalCommentCell">
                  <button
                    className={`commentOpenButton comment-${studentCommentState}${isStudentNotificationOff ? " notification-off" : ""}`}
                    onClick={() => openCommentComposer("student", student, record, effectivePreviousHomework, effectiveNextHomework)}
                    type="button"
                  >
                    학생 알림톡
                  </button>
                  <small className={`commentStatusText comment-${studentCommentState}`}>
                    {getCommentStatusLabel(record.studentComment, studentCommentSendStatus)}
                  </small>
                  <button
                    className={[
                      "notificationMuteButton",
                      record.notificationMutedStudent ? "active" : "",
                      isLessonNotificationOff && !record.notificationMutedStudent ? "planOff" : ""
                    ].filter(Boolean).join(" ")}
                    onClick={() => onToggleStudentNotificationMute?.(lesson, student, "student")}
                    title={isLessonNotificationOff ? "현재 수업 발송 계획이 알림톡 없음입니다." : ""}
                    type="button"
                  >
                    {record.notificationMutedStudent ? "제외 해제" : "알림 제외"}
                  </button>
                </div>
              </div>
            );
          })}
        </div>
      </section>

      {journalEditMode || journalManualSaveMessage ? (
        <StickySaveBar
          className="lessonJournalStickySaveBar"
          label="수업일지"
          message={journalStickySaveMessage}
          saveState={journalStickySaveState}
        >
          <button
            className="saveDraftButton"
            disabled={!journalEditMode || !hasJournalDraftChanges || journalStickySaveState === "saving"}
            onClick={saveJournalDrafts}
            type="button"
          >
            {journalStickySaveState === "saving" ? "저장 중" : "변경 저장"}
          </button>
        </StickySaveBar>
      ) : null}

      {commentModal ? (
        <CommentComposerModal
          aiModel={commentAiModel}
          aiProvider={commentAiProvider}
          audience={commentModal.audience}
          integrationStatus={integrationStatus}
          initialCommentDraft={commentModal.initialCommentDraft}
          initialSendTiming={notificationPlanMode}
          lesson={lesson}
          onChangeRecord={onChangeRecord}
          onClose={() => setCommentModal(null)}
          onPolishComment={onPolishComment}
          onSaveRecord={onSaveRecord}
          onSendComment={onSendComment}
          record={getCommentModalRecord()}
          saveState={saveStates[createLessonStudentRecordId(lesson.lessonId, commentModal.student.studentId)] ?? "idle"}
          nextHomework={commentModal.nextHomework}
          notificationTemplates={aiSettings.notificationTemplates}
          previousHomework={commentModal.previousHomework}
          student={commentModal.student}
          supplementSchedules={commentModal.supplementSchedules}
          testResultLines={commentModal.testResultLines}
        />
      ) : null}

      {prepMemoModal ? (
        <PreparationMemoModal
          acknowledgedMemoCutoff={prepMemoModal.acknowledgedMemoCutoff}
          lesson={lesson}
          onChangeRecord={onChangeRecord}
          onClose={() => setPrepMemoModal(null)}
          onSaveRecord={onSaveRecord}
          record={
            records.find((item) =>
              item.lessonStudentRecordId === createLessonStudentRecordId(lesson.lessonId, prepMemoModal.student.studentId)
            ) ?? prepMemoModal.record
          }
          saveState={saveStates[createLessonStudentRecordId(lesson.lessonId, prepMemoModal.student.studentId)] ?? "idle"}
          student={prepMemoModal.student}
          previousRecord={prepMemoModal.previousMemoRecord}
          previousLesson={prepMemoModal.previousMemoRecord ? lessons.find((item) => item.lessonId === prepMemoModal.previousMemoRecord.lessonId) : null}
          referenceRecord={prepMemoModal.referenceRecord}
          referenceLesson={prepMemoModal.referenceRecord ? lessons.find((item) => item.lessonId === prepMemoModal.referenceRecord.lessonId) : null}
        />
      ) : null}

      {studentPreviewId ? (
        <Modal
          backdropClassName="studentPortalPreviewBackdrop"
          className="studentPortalPreviewModal"
          title="학생 화면 미리보기"
          subtitle="강사가 보는 학생 포털 화면입니다."
          onClose={() => setStudentPreviewId("")}
        >
          <StudentPortalV2
            homeworks={homeworks}
            lessons={lessons}
            materials={materials}
            makeupTasks={makeupTasks}
            records={records}
            reportSnapshots={[]}
            scoreRecords={[]}
            sessionStudentId={studentPreviewId}
            students={students.filter((student) => student.studentId === studentPreviewId)}
            previewMode
            onLogout={() => setStudentPreviewId("")}
            onStudentCheckHomework={() => {}}
          />
        </Modal>
      ) : null}
    </section>
  );
}

function PreparationMemoModal({
  acknowledgedMemoCutoff = null,
  lesson,
  onChangeRecord,
  onClose,
  onSaveRecord,
  previousLesson = null,
  previousRecord = null,
  record,
  referenceLesson = null,
  referenceRecord = null,
  saveState = "idle",
  student
}) {
  const recordId = createLessonStudentRecordId(lesson.lessonId, student.studentId);
  const currentRecord = {
    ...createEmptyRecord(lesson, student),
    ...(record ?? {})
  };
  const [draftMemo, setDraftMemo] = useState(currentRecord.preparationMemo ?? "");
  const [draftStudentVisible, setDraftStudentVisible] = useState(Boolean(currentRecord.prepStudentVisible));
  const [draftParentVisible, setDraftParentVisible] = useState(Boolean(currentRecord.prepParentVisible));
  const [localCheckedMemo, setLocalCheckedMemo] = useState({
    checkedAt: currentRecord.prepMemoCheckedAt ?? "",
    sourceDate: currentRecord.prepMemoCheckedSourceDate ?? "",
    sourceRecordId: currentRecord.prepMemoCheckedSourceRecordId ?? ""
  });
  const [localSaveError, setLocalSaveError] = useState("");
  const [isClosingAfterSave, setIsClosingAfterSave] = useState(false);
  const previousMemo = previousRecord?.preparationMemo?.trim() ?? "";
  const previousLessonLabel = previousLesson
    ? `${previousLesson.date} · ${previousLesson.className}`
    : "직전 수업";
  const referenceMemo = referenceRecord?.preparationMemo?.trim() ?? "";
  const referenceLessonLabel = referenceLesson
    ? `${referenceLesson.date} · ${referenceLesson.className}`
    : "최근 참고 수업";
  const priorMemoSourceRecord = previousMemo ? previousRecord : referenceMemo ? referenceRecord : null;
  const priorMemoSourceLesson = previousMemo ? previousLesson : referenceMemo ? referenceLesson : null;
  const priorMemoSourceRecordId = getLessonStudentRecordIdentity(priorMemoSourceRecord);
  const priorMemoSourceDate = priorMemoSourceLesson?.date || getLessonStudentRecordDate(priorMemoSourceRecord);
  const effectiveCheckedSourceDate = localCheckedMemo.sourceDate || currentRecord.prepMemoCheckedSourceDate || "";
  const isPriorMemoChecked = Boolean(
    priorMemoSourceDate &&
    effectiveCheckedSourceDate &&
    priorMemoSourceDate <= effectiveCheckedSourceDate
  );
  const visiblePreviousMemo = isPriorMemoChecked ? "" : previousMemo;
  const visibleReferenceMemo = isPriorMemoChecked ? "" : referenceMemo;
  const priorMemoKind = previousMemo ? "previous" : referenceMemo ? "reference" : "";
  const visiblePriorMemo = visiblePreviousMemo || visibleReferenceMemo;
  const visiblePriorLessonLabel = visiblePreviousMemo ? previousLessonLabel : referenceLessonLabel;
  const priorMemoEyebrow = priorMemoKind === "reference" ? "REFERENCE" : "PREVIOUS";
  const priorMemoTitle = priorMemoKind === "reference" ? "최근 참고 메모" : "직전 수업메모";
  const checkedMemoDate = localCheckedMemo.sourceDate || acknowledgedMemoCutoff?.prepMemoCheckedSourceDate || "";
  const checkedMemoAt = localCheckedMemo.checkedAt || acknowledgedMemoCutoff?.prepMemoCheckedAt || "";
  const hasCheckedPriorMemo = Boolean(checkedMemoDate || isPriorMemoChecked);
  const canCheckPriorMemo = Boolean(priorMemoSourceRecordId && priorMemoSourceDate && !isPriorMemoChecked);

  function createMemoSnapshot(checkedMemo = localCheckedMemo) {
    return JSON.stringify({
      preparationMemo: draftMemo,
      prepMemoCheckedAt: checkedMemo.checkedAt || "",
      prepMemoCheckedSourceDate: checkedMemo.sourceDate || "",
      prepMemoCheckedSourceRecordId: checkedMemo.sourceRecordId || "",
      prepStudentVisible: draftStudentVisible,
      prepParentVisible: draftParentVisible
    });
  }

  const initialDraftSnapshot = JSON.stringify({
    preparationMemo: currentRecord.preparationMemo ?? "",
    prepMemoCheckedAt: currentRecord.prepMemoCheckedAt ?? "",
    prepMemoCheckedSourceDate: currentRecord.prepMemoCheckedSourceDate ?? "",
    prepMemoCheckedSourceRecordId: currentRecord.prepMemoCheckedSourceRecordId ?? "",
    prepStudentVisible: Boolean(currentRecord.prepStudentVisible),
    prepParentVisible: Boolean(currentRecord.prepParentVisible)
  });
  const lastSavedSnapshotRef = useRef(initialDraftSnapshot);

  function updateDraft(field, value) {
    if (field === "preparationMemo") setDraftMemo(value);
    if (field === "prepStudentVisible") setDraftStudentVisible(Boolean(value));
    if (field === "prepParentVisible") setDraftParentVisible(Boolean(value));
  }

  function saveMemo() {
    setLocalSaveError("");
    const draftSnapshot = createMemoSnapshot();
    if (draftSnapshot === lastSavedSnapshotRef.current && saveState !== "failed") {
      return Promise.resolve();
    }
    const nowIso = new Date().toISOString();
    return onSaveRecord(recordId, lesson, student, {
      ...currentRecord,
      preparationMemo: draftMemo,
      prepMemoCheckedAt: localCheckedMemo.checkedAt || currentRecord.prepMemoCheckedAt || "",
      prepMemoCheckedSourceDate: localCheckedMemo.sourceDate || currentRecord.prepMemoCheckedSourceDate || "",
      prepMemoCheckedSourceRecordId: localCheckedMemo.sourceRecordId || currentRecord.prepMemoCheckedSourceRecordId || "",
      prepStudentVisible: draftStudentVisible,
      prepParentVisible: draftParentVisible,
      updatedBy: "instructor_owner_001",
      updatedAt: nowIso
    }, { skipRelatedHomeworks: true, skipNotificationRefresh: true }).then((saved) => {
      if (saved !== false) lastSavedSnapshotRef.current = draftSnapshot;
      if (saved === false) setLocalSaveError("수업메모 저장 실패 · 내용을 유지한 채 다시 저장해 주세요.");
      return saved;
    });
  }

  function checkPriorMemo() {
    if (!canCheckPriorMemo) return Promise.resolve(false);
    const nowIso = new Date().toISOString();
    const checkedMemo = {
      checkedAt: nowIso,
      sourceDate: priorMemoSourceDate,
      sourceRecordId: priorMemoSourceRecordId
    };
    setLocalCheckedMemo(checkedMemo);
    const draftSnapshot = createMemoSnapshot(checkedMemo);
    return onSaveRecord(recordId, lesson, student, {
      ...currentRecord,
      preparationMemo: draftMemo,
      prepMemoCheckedAt: checkedMemo.checkedAt,
      prepMemoCheckedSourceDate: checkedMemo.sourceDate,
      prepMemoCheckedSourceRecordId: checkedMemo.sourceRecordId,
      prepStudentVisible: draftStudentVisible,
      prepParentVisible: draftParentVisible,
      updatedBy: "instructor_owner_001",
      updatedAt: nowIso
    }, { skipRelatedHomeworks: true, skipNotificationRefresh: true }).then((saved) => {
      if (saved === false) {
        setLocalCheckedMemo({
          checkedAt: currentRecord.prepMemoCheckedAt ?? "",
          sourceDate: currentRecord.prepMemoCheckedSourceDate ?? "",
          sourceRecordId: currentRecord.prepMemoCheckedSourceRecordId ?? ""
        });
        return false;
      }
      lastSavedSnapshotRef.current = draftSnapshot;
      return true;
    });
  }

  function closeMemo() {
    if (isClosingAfterSave || saveState === "saving") return;
    setIsClosingAfterSave(true);
    saveMemo().then((saved) => {
      setIsClosingAfterSave(false);
      if (saved === false) return;
      onClose();
    }).catch((error) => {
      setIsClosingAfterSave(false);
      setLocalSaveError(`수업메모 저장 실패 · ${error.message}`);
    });
  }

  return (
    <Modal
      className="preparationMemoModal"
      title={`${student.name} 수업메모`}
      subtitle={`${lesson.date} · ${lesson.className}`}
      onClose={closeMemo}
    >
      <div className="prepMemoColumns">
        <section className={["prepMemoPrevious", priorMemoKind === "reference" ? "referenceOnly" : ""].filter(Boolean).join(" ")}>
          <div className="sectionHeader slim">
            <div>
              <p className="eyebrow">{priorMemoEyebrow}</p>
              <h2>{priorMemoTitle}</h2>
            </div>
            {canCheckPriorMemo ? (
              <label className="prepMemoAcknowledgeLine">
                <input
                  checked={false}
                  disabled={saveState === "saving"}
                  onChange={(event) => {
                    if (event.target.checked) checkPriorMemo();
                  }}
                  type="checkbox"
                />
                확인 후 숨기기
              </label>
            ) : null}
          </div>
          {hasCheckedPriorMemo && !visiblePriorMemo ? (
            <div className="prepMemoCheckedState">
              <strong>✓ 이전 수업메모 확인 완료</strong>
              <span>{checkedMemoDate ? `${checkedMemoDate}까지의 메모는 다시 표시하지 않습니다.` : "확인한 이전 메모는 다시 표시하지 않습니다."}</span>
              {checkedMemoAt ? <small>{formatKoreaTimeLabel(checkedMemoAt)}</small> : null}
            </div>
          ) : null}
          {visiblePriorMemo ? (
            <>
              <span>{visiblePriorLessonLabel}</span>
              <pre>{visiblePriorMemo}</pre>
            </>
          ) : (
            !hasCheckedPriorMemo ? <EmptyState className="emptyState compact">이전 수업메모가 없습니다.</EmptyState> : null
          )}
        </section>
        <section className="prepMemoDraft">
          <label>
            강사용 메모
            <textarea
              value={draftMemo}
              onChange={(event) => updateDraft("preparationMemo", event.target.value)}
              placeholder="다음 시간에 꼭 기억해야 할 내용, 질문, 자료, 보충 포인트를 적어주세요."
            />
          </label>
          <div className="prepMemoIncludeBox">
            <strong>알림톡 작성창에서 가져오기</strong>
            <label className="checkboxLine">
              <input
                checked={draftStudentVisible}
                onChange={(event) => updateDraft("prepStudentVisible", event.target.checked)}
                type="checkbox"
              />
              학생 알림톡 작성창에 메모 가져오기
            </label>
            <label className="checkboxLine">
              <input
                checked={draftParentVisible}
                onChange={(event) => updateDraft("prepParentVisible", event.target.checked)}
                type="checkbox"
              />
              학부모 알림톡 작성창에 메모 가져오기
            </label>
            <p className="muted">
              수업메모를 저장해도 저장된 학생·학부모 최종 문구와 기존 예약 본문은 바뀌지 않습니다. 체크한 대상의 알림톡 작성창을 열 때 이 메모를 local draft로 가져오며, `최종 문구 저장` 후 `Solapi 예약 업데이트`를 눌러야 실제 예약 본문이 변경됩니다.
            </p>
          </div>
          <div className="prepMemoSaveBar">
            <button
              className={`journalSaveButton journalSave-${saveState}`}
              disabled={saveState === "saving" || isClosingAfterSave}
              onClick={saveMemo}
              type="button"
            >
              {isClosingAfterSave ? "저장 중" : getSaveButtonLabel(saveState)}
            </button>
            {localSaveError ? <span className="saveState save-failed">{localSaveError}</span> : null}
          </div>
        </section>
      </div>
    </Modal>
  );
}

function CommentComposerModal({
  aiModel,
  aiProvider,
  audience,
  integrationStatus,
  initialCommentDraft,
  initialSendTiming = "default",
  lesson,
  nextHomework,
  notificationTemplates = {},
  onChangeRecord,
  onClose,
  onPolishComment,
  onSaveRecord,
  onSendComment,
  previousHomework,
  record,
  saveState = "idle",
  student,
  supplementSchedules = [],
  testResultLines = []
}) {
  const [isSourceOpen, setIsSourceOpen] = useState(false);
  const planMode = ["default", "delay30", "none"].includes(initialSendTiming) ? initialSendTiming : "default";
  const sendDelayMinutes = planMode === "delay30" ? 30 : 0;
  const isManualResendAvailable = isLessonAlimtalkScheduleExpired(lesson, sendDelayMinutes);
  const isScheduleExpired = planMode !== "none" && isManualResendAvailable;
  const sendTiming = isManualResendAvailable ? "now" : planMode === "none" ? "none" : "scheduled";
  const isParent = audience === "parent";
  const field = isParent ? "teacherComment" : "studentComment";
  const comment = record?.[field] ?? "";
  const aiStatus = isParent ? record?.teacherCommentAiStatus : record?.studentCommentAiStatus;
  const [draftComment, setDraftComment] = useState(initialCommentDraft ?? comment);
  const [localAiStatus, setLocalAiStatus] = useState(aiStatus || "AI 대기");
  const [draftSaveState, setDraftSaveState] = useState("idle");
  const lastSavedDraftRef = useRef(comment);
  const previousAiStatusRef = useRef(aiStatus);
  const normalizedDraftSaveState = normalizeSaveState(saveState);
  const hasUnsavedDraft = draftComment !== lastSavedDraftRef.current;
  const visibleDraftSaveState =
    hasUnsavedDraft && !["dirty", "saving"].includes(normalizeSaveState(draftSaveState))
      ? "dirty"
      : normalizeSaveState(draftSaveState) !== "idle"
        ? normalizeSaveState(draftSaveState)
        : normalizedDraftSaveState;
  const title = isParent ? `${student.name} 학부모 알림톡` : `${student.name} 학생 알림톡`;
  const receiverLabel = isParent ? `${student.name} 학부모님` : student.name;
  const previewTitle = isParent ? "학부모 알림톡 미리보기" : "학생 알림톡 미리보기";
  const sendStatus = isParent ? record?.teacherCommentSendStatus : record?.studentCommentSendStatus;
  const displaySendStatus = getDisplayCommentSendStatus(sendStatus);
  const isNotificationMuted = isParent ? Boolean(record?.notificationMutedParent) : Boolean(record?.notificationMutedStudent);
  const notificationStatus = integrationStatus?.notifications;
  const audienceNotificationStatus = getAlimtalkAudienceStatus(notificationStatus, audience);
  const recipientPhone = isParent ? student.parentPhone : student.studentPhone;
  const forceDryRun = false;
  const canSendNowToRealRecipient =
    !audienceNotificationStatus?.dryRun &&
    audienceNotificationStatus?.allowRealRecipients;
  const forceTestRecipient = !canSendNowToRealRecipient;
  const actionLabel =
    isNotificationMuted
      ? "알림 제외"
      : isManualResendAvailable
        ? "수동 재발송"
      : planMode === "none"
      ? "발송 안 함"
      : planMode === "delay30"
        ? "30분 지연 예약"
        : "예약 발송";
  const safetyTone = getAlimtalkSafetyTone(audienceNotificationStatus, forceDryRun, forceTestRecipient);
  const safetyText = getAlimtalkSafetyText(audienceNotificationStatus, forceDryRun, forceTestRecipient);
  const missingNotificationEnv = notificationStatus?.missing ?? [];
  const defaultScheduledDate = getLessonAlimtalkScheduledDate(lesson, 0, { allowPastFallback: false });
  const delayedScheduledDate = getLessonAlimtalkScheduledDate(lesson, 30, { allowPastFallback: false });
  const currentPlanLabel =
    planMode === "none"
      ? "알림톡 없음"
      : isScheduleExpired
        ? `${planMode === "delay30" ? "30분 지연" : "기본 예약"} 시간 지남 · ${formatKoreaTimeLabel(planMode === "delay30" ? delayedScheduledDate : defaultScheduledDate)}`
      : planMode === "delay30"
        ? `30분 지연 ${formatKoreaTimeLabel(delayedScheduledDate)}`
        : `기본 예약 ${formatKoreaTimeLabel(defaultScheduledDate)}`;
  const sourceText = buildCommentSourceText({
    audience,
    lesson,
    nextHomework,
    notificationTemplates,
    previousHomework,
    record,
    student,
    supplementSchedules,
    testResultLines
  });
  const generatedPreviewText = buildCommentPreviewText({
    audience,
    comment: draftComment,
    lesson,
    nextHomework,
    notificationTemplates,
    previousHomework,
    record,
    student,
    supplementSchedules,
    testResultLines
  });
  useEffect(() => {
    const nextComment = record?.[field] ?? "";
    setDraftComment(initialCommentDraft ?? nextComment);
    lastSavedDraftRef.current = nextComment;
    previousAiStatusRef.current = aiStatus;
    setDraftSaveState("idle");
    setLocalAiStatus(aiStatus || "AI 대기");
  }, [audience, student.studentId]);

  useEffect(() => {
    const previousAiStatus = previousAiStatusRef.current;
    previousAiStatusRef.current = aiStatus;
    if (previousAiStatus === "AI 수정 중" && aiStatus && aiStatus !== "AI 수정 중") {
      setDraftComment(record?.[field] ?? "");
    }
  }, [aiStatus, field, record]);

  function handleClose() {
    if (hasUnsavedDraft && typeof window !== "undefined" && !window.confirm("저장하지 않은 최종 문구가 있습니다. 닫을까요?")) {
      return;
    }
    onClose();
  }

  async function handlePolishClick() {
    const nextRecord = { ...(record ?? {}), [field]: draftComment };
    const rawText = normalizeMessageText(draftComment) || normalizeMessageText(sourceText) || normalizeMessageText(generatedPreviewText);
    setLocalAiStatus("AI 수정 중");
    const result = await onPolishComment(lesson, student, nextRecord, audience, aiProvider, aiModel, { persist: false, rawText });
    if (result?.ok && result.polishedText) {
      setDraftComment(result.polishedText);
      setDraftSaveState("dirty");
      setLocalAiStatus(`완료 · ${result.provider}`);
      return;
    }
    setLocalAiStatus(`실패 · ${result?.error || "AI 수정 실패"}`);
  }

  async function handleSaveDraftClick() {
    const recordId = createLessonStudentRecordId(lesson.lessonId, student.studentId);
    const nextRecord = { ...(record ?? {}), [field]: draftComment };
    const recordToSave = {
      ...createEmptyRecord(lesson, student),
      ...nextRecord,
      lessonStudentRecordId: recordId,
      lessonId: lesson.lessonId,
      studentId: student.studentId,
      [field]: draftComment,
      ...(field === "teacherComment" ? { teacherCommentSendStatus: "" } : {}),
      ...(field === "studentComment" ? { studentCommentSendStatus: "" } : {}),
      updatedBy: "instructor_owner_001",
      updatedAt: new Date().toISOString()
    };
    setDraftSaveState("saving");
    const saved = await onSaveRecord?.(recordId, lesson, student, recordToSave, {
      skipNotificationRefresh: true,
      skipRelatedHomeworks: true,
      verifyFields: [field]
    });
    if (saved === false) {
      setDraftSaveState("failed");
      return false;
    }
    lastSavedDraftRef.current = draftComment;
    setDraftSaveState("saved");
    return true;
  }

  function handleSendClick() {
    if (hasUnsavedDraft) return;
    const nextRecord = { ...(record ?? {}), [field]: draftComment };
    onSendComment(lesson, student, nextRecord, audience, {
      delayMinutes: sendDelayMinutes,
      forceDryRun,
      forceTestRecipient,
      manualCommentBody: draftComment,
      manualPreviewBody: generatedPreviewText,
      resendReason: isManualResendAvailable ? "예약 시간 경과 후 수동 재발송" : "",
      sendTiming
    });
  }

  return (
    <Modal className="commentComposerModal" title={title} subtitle={`${lesson.date} · ${lesson.className}`} onClose={handleClose}>
      <div className="commentComposerGrid">
        <section className="commentDraftPanel">
          <div className="sectionHeader slim">
            <div>
              <p className="eyebrow">FINAL</p>
              <h2>최종 알림톡 문구</h2>
            </div>
            <span className="countBadge">{isParent ? "학부모용" : "학생용"}</span>
          </div>
          <div className="commentSourceToggle">
            <button className="softButton mini" onClick={() => setIsSourceOpen((current) => !current)} type="button">
              {isSourceOpen ? "원본 메모 접기" : "원본 메모 보기"}
            </button>
            <span>수업메모와 일정 정보는 AI 수정 참고용으로 보관됩니다.</span>
          </div>
          {isSourceOpen ? (
            <pre className="templatePreviewText commentSourcePreview">{sourceText}</pre>
          ) : null}
          <textarea
            className="commentComposerTextarea"
            value={draftComment}
            onChange={(event) => setDraftComment(event.target.value)}
            placeholder={isParent ? "학부모님께 실제로 보낼 최종 문구를 적어주세요." : "학생에게 실제로 보낼 최종 문구를 적어주세요."}
          />
          <div className="commentComposerStatusRow">
            <InlineSaveStatus label="최종 문구" saveState={visibleDraftSaveState} />
            <small className="muted">{localAiStatus}</small>
          </div>
          <div className="commentComposerActions">
            <button
              className="softButton"
              disabled={localAiStatus === "AI 수정 중"}
              onClick={handlePolishClick}
              type="button"
            >
              {localAiStatus === "AI 수정 중" ? "AI 수정 중..." : "AI 수정"}
            </button>
            <button
              className="saveDraftButton"
              disabled={!hasUnsavedDraft || draftSaveState === "saving"}
              onClick={handleSaveDraftClick}
              type="button"
            >
              {draftSaveState === "saving" ? "저장 중" : "최종 문구 저장"}
            </button>
            <button
              className="sendButton"
              disabled={hasUnsavedDraft || isNotificationMuted || (planMode === "none" && !isManualResendAvailable)}
              onClick={handleSendClick}
              title={hasUnsavedDraft ? "최종 문구 저장 후 예약/발송할 수 있습니다." : ""}
              type="button"
            >
              {hasUnsavedDraft ? "저장 후 가능" : actionLabel}
            </button>
          </div>
          <div className="currentSchedulePlan" aria-label="현재 수업 발송 계획">
            <span>현재 수업 발송 계획</span>
            <strong>{currentPlanLabel}</strong>
            <small>
              {isNotificationMuted
                ? "이 학생의 해당 알림톡은 개별 제외 상태입니다."
                : isManualResendAvailable
                  ? "예약 계획과 관계없이 버튼을 누르면 즉시 수동 재발송합니다."
                  : "발송 버튼은 현재 수업 발송 계획대로 예약합니다."}
            </small>
          </div>
          <div className={`alimtalkSafetyBox ${safetyTone}`}>
            <strong>{safetyText}</strong>
            <span>수신 대상: {receiverLabel} · 등록 번호: {recipientPhone || "번호 없음"}</span>
            {missingNotificationEnv.length ? <span>미입력 환경변수: {missingNotificationEnv.join(", ")}</span> : null}
          </div>
          <small className="muted">발송 수신 기준: {canSendNowToRealRecipient ? "등록된 실제 번호" : "테스트 번호 또는 dry-run"}</small>
          <small className="muted">{displaySendStatus || "발송 전"}</small>
        </section>

        <section className="commentPreviewPanel">
          <div className="sectionHeader slim">
            <div>
              <p className="eyebrow">PREVIEW</p>
              <h2>{previewTitle}</h2>
            </div>
          </div>
          <pre className="templatePreviewText commentTemplatePreview">{generatedPreviewText}</pre>
        </section>
      </div>
    </Modal>
  );
}

function AttendanceModal({ item, lateGraceMinutes = 5, onClose, onSave }) {
  const { lesson, record, student } = item;
  const attendanceDateMismatch = getAttendanceDateMismatch(record, lesson);
  const editableRecord = attendanceDateMismatch ? clearAttendanceFields(record) : record;
  const [attendanceStatus, setAttendanceStatus] = useState(getManualAttendanceInitialStatus(editableRecord));
  const [checkInTime, setCheckInTime] = useState(editableRecord.checkInTime || formatKoreaTimeFromIso(editableRecord.checkInAt) || "");
  const [checkOutTime, setCheckOutTime] = useState(editableRecord.checkOutTime || formatKoreaTimeFromIso(editableRecord.checkOutAt) || "");
  const [attendanceReason, setAttendanceReason] = useState(editableRecord.attendanceReason ?? "");
  const [pendingSave, setPendingSave] = useState(null);
  const [confirmStep, setConfirmStep] = useState("");
  const [saveError, setSaveError] = useState("");
  const [isSaving, setIsSaving] = useState(false);
  const calculatedLateMinutes = attendanceStatus === "late"
    ? calculateLateMinutesFromLessonTime(lesson, checkInTime, lateGraceMinutes)
    : "";
  const effectiveLateMinutes = attendanceStatus !== "late"
    ? ""
    : calculatedLateMinutes !== ""
      ? calculatedLateMinutes
      : editableRecord.lateMinutes ?? "";
  const isWithinLateGrace = attendanceStatus === "late" && effectiveLateMinutes !== "" && Number(effectiveLateMinutes) <= 0;
  const effectiveAttendanceStatus = isWithinLateGrace ? "present" : attendanceStatus;
  const values = {
    attendanceStatus: effectiveAttendanceStatus,
    lateMinutes: effectiveAttendanceStatus === "late" ? effectiveLateMinutes : "",
    checkInTime,
    checkOutTime,
    attendanceReason
  };
  const hasKioskRecord = !attendanceDateMismatch && hasTabletAttendanceRecord(record);
  const hasChanged = hasAttendanceModalChanges(editableRecord, values);

  function requestSave() {
    setSaveError("");
    const nextSave = { values, options: {} };
    if (hasKioskRecord && hasChanged) {
      setPendingSave(nextSave);
      setConfirmStep("change");
      return;
    }
    setPendingSave(nextSave);
    setConfirmStep("saveMode");
  }

  function confirmManualChange() {
    setConfirmStep("saveMode");
  }

  async function finishConfirmedSave(sendAlimtalk) {
    if (isSaving) return;
    const nextSave = pendingSave ?? { values, options: {} };
    setIsSaving(true);
    setSaveError("");
    try {
      const saved = await onSave(lesson, student, nextSave.values, { ...nextSave.options, sendAlimtalk });
      if (!saved) {
        setSaveError("출결 저장에 실패했습니다. 잠시 후 다시 눌러 주세요.");
      }
    } catch (error) {
      setSaveError(
        String(error.message || "").startsWith("결석 출결은 저장됐지만")
          ? error.message
          : `출결 저장에 실패했습니다. ${error.message}`
      );
    } finally {
      setIsSaving(false);
    }
  }

  return (
    <Modal title={`${student.name} 출결 체크`} subtitle="지각/결석이면 시간과 사유를 남깁니다." onClose={onClose}>
      <div className="typeTabs">
        {[
          ["present", "등원"],
          ["late", "지각"],
          ["checkout", "하원"],
          ["absent", "결석"]
        ].map(([value, label]) => (
          <button className={attendanceStatus === value ? "active" : ""} key={value} onClick={() => setAttendanceStatus(value)} type="button">
            {label}
          </button>
        ))}
      </div>
      <div className="fieldGrid">
        <label>
          등원 시각
          <input
            type="time"
            value={checkInTime}
            onChange={(event) => setCheckInTime(event.target.value)}
          />
          <small>출결을 못 찍은 학생은 실제 등원 시각을 입력하세요. 지각 분은 수업 시작 기준으로 자동 계산됩니다.</small>
        </label>
        <label>
          하원 시각
          <input
            type="time"
            value={checkOutTime}
            onChange={(event) => setCheckOutTime(event.target.value)}
          />
          <small>하원 처리를 못 찍은 학생은 실제 하원 시각을 입력하세요.</small>
        </label>
        <label>
          사유
          <input value={attendanceReason} onChange={(event) => setAttendanceReason(event.target.value)} placeholder="예: 학교 동아리" />
        </label>
      </div>
      {isWithinLateGrace ? (
        <div className="attendanceSourceNotice">
          지각 유예시간 {lateGraceMinutes}분 안의 등원이라 저장 시 정상 등원으로 처리됩니다.
        </div>
      ) : null}
      {hasKioskRecord ? (
        <div className="attendanceSourceNotice">
          태블릿에서 기록된 출결입니다. 수동으로 바꾸면 확인 후 저장됩니다.
        </div>
      ) : null}
      {attendanceDateMismatch ? (
        <div className="attendanceSourceNotice warning">
          저장된 출결 날짜가 수업 날짜와 다릅니다. 출결 {attendanceDateMismatch.mismatchedDates.map(formatShortDateLabel).join(", ")} · 수업 {formatShortDateLabel(attendanceDateMismatch.lessonDate)}. 저장하면 이 수업 날짜 기준으로 새 출결을 기록합니다.
        </div>
      ) : null}
      {confirmStep === "change" ? (
        <div className="attendanceConfirmPanel">
          <strong>태블릿 출결 기록을 변경하시겠습니까?</strong>
          <p>실수 방지를 위해 한 번 더 확인합니다. 저장하면 현재 화면의 출결 상태와 사유로 덮어씁니다.</p>
          <div className="attendanceConfirmActions">
            <button className="softButton" onClick={() => setConfirmStep("")} type="button">
              취소
            </button>
            <button className="primaryButton" onClick={confirmManualChange} type="button">
              변경하기
            </button>
          </div>
        </div>
      ) : null}
      {confirmStep === "saveMode" ? (
        <div className="attendanceConfirmPanel">
          <strong>출결을 어떻게 저장할까요?</strong>
          <p>
            {values.attendanceStatus === "absent"
              ? "결석 기록만 저장하거나, 저장 후 학부모 결석 알림톡을 다음 예약 가능한 정각에 예약할 수 있습니다."
              : "출결 기록만 저장하거나, 저장 후 학부모에게 출결 알림톡까지 즉시 발송할 수 있습니다."}
          </p>
          {saveError ? <p className="apiErrorBox">{saveError}</p> : null}
          <div className="attendanceConfirmActions">
            <button className="softButton" disabled={isSaving} onClick={() => finishConfirmedSave(false)} type="button">
              {isSaving ? "저장 중..." : "저장만"}
            </button>
            <button className="primaryButton" disabled={isSaving} onClick={() => finishConfirmedSave(true)} type="button">
              {isSaving
                ? "저장 중..."
                : values.attendanceStatus === "absent"
                  ? "저장 후 다음 정각 알림톡 예약"
                  : "저장 후 출결 알림톡 즉시 발송"}
            </button>
          </div>
        </div>
      ) : null}
      {!confirmStep ? (
        <div className="attendanceModalActions">
          <button className="primaryButton full" onClick={() => requestSave()} type="button">
            출결 저장
          </button>
        </div>
      ) : null}
    </Modal>
  );
}

function hasTabletAttendanceRecord(record = {}) {
  return Boolean(record.checkInAt || record.checkInTime || record.checkOutAt || record.checkOutTime || record.updatedBy === "attendance_kiosk");
}

function getManualAttendanceInitialStatus(record = {}) {
  const status = record?.attendanceStatus;
  if (status && status !== "pending") return status;
  if (record?.checkOutAt || record?.checkOutTime) return "checkout";
  return "present";
}

function normalizeAttendanceField(value) {
  return String(value ?? "").trim();
}

function hasAttendanceModalChanges(record = {}, values = {}) {
  return (
    normalizeAttendanceField(record.attendanceStatus ?? "present") !== normalizeAttendanceField(values.attendanceStatus ?? "present") ||
    normalizeAttendanceField(record.lateMinutes) !== normalizeAttendanceField(values.lateMinutes) ||
    normalizeAttendanceField(record.checkInTime || formatKoreaTimeFromIso(record.checkInAt)) !== normalizeAttendanceField(values.checkInTime) ||
    normalizeAttendanceField(record.checkOutTime || formatKoreaTimeFromIso(record.checkOutAt)) !== normalizeAttendanceField(values.checkOutTime) ||
    normalizeAttendanceField(record.attendanceReason) !== normalizeAttendanceField(values.attendanceReason)
  );
}

function getAttendanceActionLabel(result = {}) {
  if (result.mode === "completed") return "이미 하원";
  if (result.mode === "checkOut") return "하원";
  const status = result.record?.attendanceStatus ?? "";
  if (status === "late") return "지각 등원";
  if (status === "absent") return "결석";
  if (status === "excused") return "인정결석";
  return "등원";
}

function AttendanceKiosk({
  isLoading = false,
  isStandalone = false,
  lessons = [],
  records = [],
  students,
  onAttendanceCheck,
  onAttendancePreview,
  onBack
}) {
  const [pin, setPin] = useState("");
  const [pendingPreview, setPendingPreview] = useState(null);
  const [result, setResult] = useState(null);
  const [isSubmitting, setIsSubmitting] = useState(false);

  async function runAttendancePreview(nextPin) {
    if (isSubmitting) return;
    setIsSubmitting(true);
    try {
      const nextPreview = await onAttendancePreview(nextPin);
      if (nextPreview.ok) {
        setPendingPreview({ ...nextPreview, pin: nextPin });
        setResult(null);
        setPin("");
      } else {
        setResult(nextPreview);
      }
    } catch (error) {
      setResult({ ok: false, message: error.message || "출결 확인에 실패했습니다." });
    } finally {
      setIsSubmitting(false);
    }
  }

  async function selectPendingPreviewLesson(candidate) {
    const lessonId = candidate?.lesson?.lessonId || candidate?.attendanceLesson?.lessonId;
    if (!pendingPreview?.pin || !lessonId || isSubmitting) return;
    setIsSubmitting(true);
    try {
      const nextPreview = await onAttendancePreview(pendingPreview.pin, {
        lessonId,
        studentId: pendingPreview.student?.studentId
      });
      if (nextPreview.ok) {
        setPendingPreview({ ...nextPreview, pin: pendingPreview.pin });
        setResult(null);
      } else {
        setResult(nextPreview);
        setPendingPreview(null);
      }
    } catch (error) {
      setResult({ ok: false, message: error.message || "수업 선택 확인에 실패했습니다." });
      setPendingPreview(null);
    } finally {
      setIsSubmitting(false);
    }
  }

  async function confirmAttendanceCheck() {
    if (!pendingPreview || isSubmitting) return;
    if (pendingPreview.mode === "completed") {
      setPendingPreview(null);
      return;
    }
    setIsSubmitting(true);
    try {
      const nextResult = await onAttendanceCheck(pendingPreview.pin, {
        action: pendingPreview.action,
        attendanceStatus: pendingPreview.record?.attendanceStatus,
        checkInTime: pendingPreview.record?.checkInTime,
        checkOutTime: pendingPreview.record?.checkOutTime,
        lateMinutes: pendingPreview.record?.lateMinutes,
        lessonId: pendingPreview.lesson?.lessonId,
        studentId: pendingPreview.student?.studentId
      });
      setPendingPreview(null);
      if (!nextResult?.ok) {
        setResult(nextResult);
      } else {
        setResult(null);
      }
    } catch (error) {
      setResult({ ok: false, message: error.message || "출결 저장에 실패했습니다." });
      setPendingPreview(null);
    } finally {
      setIsSubmitting(false);
    }
  }

  function submitPin(event) {
    event?.preventDefault();
    if (isLoading || isSubmitting || pendingPreview) return;
    runAttendancePreview(pin);
  }

  function pressKey(value) {
    if (isLoading || isSubmitting || pendingPreview) return;
    if (value === "backspace") {
      setPin((current) => current.slice(0, -1));
      return;
    }
    if (value === "clear") {
      setPin("");
      return;
    }
    setPin((current) => `${current}${value}`.replaceAll(/\D/g, "").slice(0, 4));
  }

  const resultTitle = result?.ok ? getAttendanceActionLabel(result) : "출결 체크 실패";
  const resultDetail = result?.ok
    ? `${result.student?.name ?? ""} · ${formatLessonDisplayName(result.lesson)} · ${result.checkedTime || ""}`
    : result?.message;
  const previewRequiresLessonSelection = Boolean(pendingPreview?.requiresLessonSelection || pendingPreview?.mode === "selectLesson");
  const previewLessonCandidates = Array.isArray(pendingPreview?.lessonCandidates) ? pendingPreview.lessonCandidates : [];
  const previewActionLabel = pendingPreview
    ? previewRequiresLessonSelection
      ? "수업 선택"
      : getAttendanceActionLabel(pendingPreview)
    : "";
  const previewDetail = pendingPreview?.ok
    ? previewRequiresLessonSelection
      ? `${pendingPreview.student?.name ?? ""} · 수업 선택 · ${pendingPreview.checkedTime || ""}`
      : `${pendingPreview.student?.name ?? ""} · ${formatLessonDisplayName(pendingPreview.lesson)} · ${pendingPreview.checkedTime || ""}`
    : "";

  return (
    <section className={isStandalone ? "attendanceKioskPage standalone" : "attendanceKioskPage"}>
      <div className="attendanceKioskCard">
        <div className="attendanceKioskHeader">
          <div>
            <p className="eyebrow">{academyBrandName} ATTENDANCE</p>
            <h1>출결 체크</h1>
            <p className="muted">{isLoading ? "출결 데이터를 불러오는 중입니다." : "학생 휴대폰 번호 뒤 4자리를 입력하세요."}</p>
          </div>
          {onBack ? <button className="iconButton" onClick={onBack} type="button">×</button> : null}
        </div>
        <form className="attendancePinForm" onSubmit={submitPin}>
          <input
            autoFocus
            inputMode="numeric"
            maxLength={4}
            disabled={isLoading || isSubmitting || Boolean(pendingPreview)}
            value={pin}
            onChange={(event) => {
              setPin(event.target.value.replaceAll(/\D/g, "").slice(0, 4));
            }}
            placeholder={isLoading || isSubmitting ? "대기" : "뒤 4자리"}
          />
          <button className="primaryButton" disabled={isLoading || isSubmitting || Boolean(pendingPreview) || pin.length !== 4} type="submit">
            {isSubmitting ? "확인 중" : "확인"}
          </button>
        </form>

        <div className={isLoading || isSubmitting || pendingPreview ? "attendanceNumberPad disabled" : "attendanceNumberPad"} aria-label="출결 번호 입력 키패드">
          {["1", "2", "3", "4", "5", "6", "7", "8", "9"].map((value) => (
            <button disabled={isLoading || isSubmitting || Boolean(pendingPreview)} key={value} onClick={() => pressKey(value)} type="button">{value}</button>
          ))}
          <button className="secondaryKey" disabled={isLoading || isSubmitting || Boolean(pendingPreview)} onClick={() => pressKey("clear")} type="button">지움</button>
          <button disabled={isLoading || isSubmitting || Boolean(pendingPreview)} onClick={() => pressKey("0")} type="button">0</button>
          <button className="secondaryKey" disabled={isLoading || isSubmitting || Boolean(pendingPreview)} onClick={() => pressKey("backspace")} type="button">⌫</button>
        </div>
      </div>

      {pendingPreview ? (
        <Modal
          className="attendanceResultModal"
          hideCloseButton
          subtitle={previewDetail}
          title="출결 확인"
        >
          <div className="attendanceResultContent">
            <strong>{previewActionLabel}</strong>
            {previewRequiresLessonSelection ? (
              <>
                <p>오늘 수업이 2개 이상입니다. 등원 처리할 수업을 선택하세요.</p>
                <div className="attendanceLessonChoiceGrid">
                  {previewLessonCandidates.map((candidate) => {
                    const lesson = candidate.attendanceLesson || candidate.lesson || {};
                    const statusText = candidate.hasCheckout
                      ? "하원 완료"
                      : candidate.hasArrival
                        ? "등원 기록 있음"
                        : candidate.isLatest
                          ? "오늘 마지막 수업"
                          : "등원 대상";
                    return (
                      <button
                        className={candidate.isLatest ? "attendanceLessonChoiceButton latest" : "attendanceLessonChoiceButton"}
                        disabled={isSubmitting}
                        key={candidate.lesson?.lessonId || candidate.attendanceLesson?.lessonId}
                        onClick={() => selectPendingPreviewLesson(candidate)}
                        type="button"
                      >
                        <strong>{formatLessonDisplayName(lesson) || "수업"}</strong>
                        <small>{statusText}</small>
                      </button>
                    );
                  })}
                </div>
              </>
            ) : (
              <>
                <div className="attendancePreviewSummary">
                  <span><small>학생</small><b>{pendingPreview.student?.name ?? "-"}</b></span>
                  <span><small>수업</small><b>{formatLessonDisplayName(pendingPreview.lesson) || "-"}</b></span>
                  <span><small>시간</small><b>{pendingPreview.checkedTime || "-"}</b></span>
                </div>
                <div className="attendanceConfirmActions single">
                  <button className="primaryButton" disabled={isSubmitting} onClick={confirmAttendanceCheck} type="button">
                    {isSubmitting ? "저장 중..." : "확인"}
                  </button>
                </div>
              </>
            )}
          </div>
        </Modal>
      ) : null}

      {result ? (
        <Modal
          className={result.ok ? "attendanceResultModal success" : "attendanceResultModal error"}
          onClose={() => setResult(null)}
          subtitle={resultDetail}
          title={resultTitle}
        >
          <div className="attendanceResultContent">
            <strong>{result.message}</strong>
            <p>번호를 확인한 뒤 다시 입력해 주세요.</p>
            <button className="primaryButton" onClick={() => setResult(null)} type="button">닫기</button>
          </div>
        </Modal>
      ) : null}
    </section>
  );
}

function TeacherLessonHub({
  lessons,
  records,
  saveStates,
  selectedDate,
  selectedLesson,
  selectedLessonId,
  students,
  homeworks,
  onAddLesson,
  onChangeRecord,
  onDateSelect,
  onDeleteLesson,
  onEditLesson,
  onOpenReport,
  onSaveRecord,
  onSelectLesson
}) {
  return (
    <>
      <header className="pageTop teacherCalendarTop">
        <button className="iconButton" type="button">‹</button>
        <h1>{formatMonthTitle(selectedDate)}</h1>
        <button className="iconButton" type="button">›</button>
        <button className="primaryButton" onClick={onAddLesson} type="button">+ 수업 등록</button>
      </header>

      <section className="calendarShell teacherCalendarShell">
        <TeacherMonthCalendar
          lessons={lessons}
          selectedDate={selectedDate}
          selectedLessonId={selectedLessonId}
          onDateSelect={onDateSelect}
          onSelectLesson={onSelectLesson}
        />
      </section>

      <section className="lessonJournalArea">
        {selectedLesson ? (
          <>
            <div className="panel lessonJournalToolbar">
              <div>
                <h2>{selectedLesson.className}</h2>
                <p className="muted">
                  {selectedLesson.date} · {formatLessonTimeRange(selectedLesson)} · {students.length}명
                </p>
              </div>
              <div className="lessonToolbarActions">
                <button className="softButton" onClick={() => onEditLesson(selectedLesson)} type="button">
                  수업 수정
                </button>
                <button className="dangerButton" onClick={() => onDeleteLesson(selectedLesson.lessonId)} type="button">
                  수업 취소 처리
                </button>
              </div>
            </div>
            <LessonDetail
              lesson={selectedLesson}
              records={records}
              saveStates={saveStates}
              students={students}
              homeworks={homeworks}
              onChangeRecord={onChangeRecord}
              onOpenReport={onOpenReport}
              onSaveRecord={onSaveRecord}
            />
          </>
        ) : (
          <EmptyState className="panel emptyState">{selectedDate}에 등록된 수업이 없습니다.</EmptyState>
        )}
      </section>
    </>
  );
}

